  'person',
  '{"document_kind":"tour_product_full_page_v1","schema_version":7,"slug":"seoul-seoraksan-nami-island-morning-calm-day-tour","locale":"ja","product_id":"seoul-seoraksan-nami-island-morning-calm-day-tour","seo":{"pageTitle":"ソウル日帰りツアー：雪岳山・南怡島・晨静苑 | AtoC Korea","metaDescription":"ソウル発13時間バス日帰りツアー：雪岳山国立公園（ユネスコ生物圏保護区）、南怡島（冬のソナタ）、晨静苑 ― 入場料すべて込み。","primaryKeywords":["ソウル発雪岳山日帰りツアー","南怡島日帰り旅行","晨静苑ツアー","ソウル日帰りツアー 雪岳山","雪岳山・南怡島 1日ツアー"],"ogImage":"https://www.atockorea.com/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp","title":"ソウル日帰りツアー · 雪岳山 ＋ 南怡島 ＋ 晨静苑 | AtoC Korea","description":"ソウル発バスツアーで、韓国で最も名高い山（雪岳山）、最も写真に撮られる島（南怡島）、そして唯一無二のプライベートガーデン（晨静苑）を、わずか13時間で巡る日帰りツアーです。"},"catalog_card":{"thumbnail":"/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp","title":"ソウル発：雪岳山 ＋ 南怡島 ＋ 晨静苑","priceLabel":"お一人様 US$59〜（通常$82、28%割引）","shortCardDescription":"ソウル発13時間バス日帰りツアーで、韓国で最も写真に撮られる3大スポットを訪問：雪岳山国立公園（韓国唯一のユネスコ生物圏保護区）、南怡島（冬のソナタのメタセコイア並木）、晨静苑（5,000種類の植物を誇る韓国を代表するプライベート樹木園）。入場料すべて込み、英語ガイド付き、弘大入口駅または明洞駅よりピックアップ。","tags":["ソウルからの日帰り旅行","バスツアー","自然・庭園","韓流の名所","入場料すべて込み"],"rating":0,"reviewCount":0,"slug":"seoul-seoraksan-nami-island-morning-calm-day-tour","subtitle":"雪岳山、南怡島の並木道、晨静苑のテーマガーデンを、ソウル発13時間の日帰りツアーでまとめて堪能。","region":"ソウル → 江原道 → 京畿道","duration":"13時間","stopsCount":3,"badges":["ソウルからの日帰り旅行","大型バス","入場料すべて込み","13時間の行程"],"heroImage":"/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp"},"headlineLine1":"ソウル日帰りツアー","headlineLine2":"雪岳山（ソラクサン）＋南怡島（ナミ島）＋モーニングカーム","price":{"amountLabel":"","currency":"USD","per":"person","salePriceUsd":null,"originalPriceUsd":null,"discountPercent":null},"hero":{"imageUrl":"/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp","imagePosition":"center 40%","tagline":"ソウルから13時間のバスツアーで巡る、韓国で最も写真に収められる日帰りスポット3選：雪岳山、南怡島の並木道、そして晨静苑（ガーデン・オブ・モーニングカーム）","pills":["ソウルからの日帰り旅行","自然＋韓流＋庭園","バスツアー"],"meta":{"duration":"13時間","region":"ソウル → 江原道（カンウォンド）→ 京畿道（キョンギド）","stops":"3スポット","rating":0,"ratingStars":5}},"subnavItems":[{"id":"overview","label":"概要"},{"id":"itinerary","label":"旅程"},{"id":"details","label":"詳細"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"口コミ"}],"glanceItems":[{"icon":"clock","label":"所要時間","value":"13時間"},{"icon":"camera","label":"フォトジェニック度","value":"非常に高い","level":5},{"icon":"mountain","label":"景観","value":"非常に高い","level":5},{"icon":"footprints","label":"徒歩量","value":"普通","level":3},{"icon":"cloud-rain","label":"雨天時の適合度","value":"普通","level":3},{"icon":"users","label":"ファミリー向け度","value":"良い","level":4},{"icon":"gauge","label":"ペース","value":"バランス","level":4}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp","location":"雪岳山国立公園","alt":"雪岳山国立公園 — on-route photo","caption":"雪岳山国立公園"},{"id":2,"type":"photo","src":"/images/tours/nami-island/kakaotalk-20260510-222949305-04.webp","location":"南怡島（ナミソム）","alt":"南怡島（ナミソム） — gallery image 1","caption":"南怡島（ナミソム） — photo 1"},{"id":3,"type":"photo","src":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-36-31.webp","location":"晨靜苑","alt":"晨靜苑 — gallery image 1","caption":"晨靜苑 — photo 1"},{"id":4,"type":"photo","src":"/images/tours/seoraksan-national-park/seoraksan-sinheungsa-ulsanbawi.webp","location":"雪岳山国立公園","alt":"雪岳山国立公園 — on-route photo","caption":"雪岳山国立公園"},{"id":5,"type":"photo","src":"/images/tours/seoraksan-national-park/photo-001.webp","location":"雪岳山国立公園","alt":"雪岳山国立公園 — on-route photo","caption":"雪岳山国立公園"},{"id":6,"type":"photo","src":"/images/tours/nami-island/kakaotalk-20260510-222949305-05.webp","location":"南怡島（ナミソム）","alt":"南怡島（ナミソム） — gallery image 2","caption":"南怡島（ナミソム） — photo 2"},{"id":7,"type":"photo","src":"/images/tours/nami-island/chatgpt-image-2026-5-11-01-12-05.webp","location":"南怡島（ナミソム）","alt":"南怡島（ナミソム） — gallery image 3","caption":"南怡島（ナミソム） — photo 3"},{"id":8,"type":"photo","src":"/images/tours/nami-island/nami-metasequoia-sunset-lake.webp","location":"南怡島（ナミソム）","alt":"南怡島（ナミソム） — gallery image 6","caption":"南怡島（ナミソム） — photo 6"},{"id":9,"type":"photo","src":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-43-58.webp","location":"晨靜苑","alt":"晨靜苑 — gallery image 2","caption":"晨靜苑 — photo 2"},{"id":10,"type":"photo","src":"/images/tours/garden-of-morning-calm/garden-of-morning-calm-flowers.webp","location":"晨靜苑","alt":"晨靜苑 — gallery image 3","caption":"晨靜苑 — photo 3"},{"id":11,"type":"photo","src":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-11-01-09-33.webp","location":"晨靜苑","alt":"晨靜苑 — gallery image 4","caption":"晨靜苑 — photo 4"}],"itineraryStops":[{"name":"乗車場所（弘大入口駅または明洞駅）","time":"06:00 / 06:30","number":1,"category":"コーチ（大型バス）での送迎","duration":"乗車受付時間：30分","timeUsed":["出発予定時刻の5分前に乗車場所へご到着ください（約5分）","目印のスターバックス／ノースフェイス前でAtoC Koreaのコーチをご確認ください（約5分）","乗車列に並び、大型コーチに乗車（約10分）","乗車時に韓国語・英語併記の行程カードを配布"],"whyOnRoute":"2か所の早朝乗車ポイントは、ソウルの2大ホテル・ホステル集積エリアをカバーしています。弘大エリア（麻浦区：若い旅行者や短期滞在者に人気）と明洞（中区：ロッテ・新羅・ウェスティンホテル周辺の伝統的な観光エリア）です。弘大06:00発・明洞06:30発は、ソウルの地下鉄運行時間（2号線は約05:30始発）を考慮した上で最も早い現実的な乗車時刻であり、雪岳山に10:00前に到着して充実した3時間の公園見学を実現するための唯一の手段です。弘大→明洞の順は、オリンピック大路→ソウル-襄陽高速道路を経由した自然な北東方向ルートです。","description":"ソウルの2か所の集合ポイントのいずれかでご乗車ください。**(1) スターバックス弘大入口駅8番出口（麻浦区）** 06:00集合 — 8番出口を上がるとすぐ目の前にスターバックスがあり、寒い日には前夜22:00まで店内でお待ちいただけます。または **(2) 明洞駅2番出口（中区）** 06:30集合 — 出口すぐ隣のノースフェイス旗艦店が目印です。\n\n両乗車ポイントは同じ大型コーチを共有し、弘大からのお客様が先に乗車します。定刻出発のため、ご選択の乗車ポイントには**出発予定時刻の5分前**までにお越しください。13時間の行程は、雪岳山への10:00前到着が前提です。乗車時にドライバーガイドが韓国語・英語の行程カードを配布し、当日のスケジュール・トイレ休憩・通常19:00の帰着予定時刻をご案内します。\n\n明洞（最終乗車ポイント）を出発後、コーチはオリンピック大路を東へ進み、ソウル-襄陽高速道路に移行して約2時間30分で雪岳山へ向かいます。"},{"name":"雪岳山国立公園","time":"≈ 10:00","number":2,"category":"大韓民国国立公園 — 韓国3大名山のひとつ（1,708m）・ユネスコ生物圏保全地域","duration":"180分（3時間）","timeUsed":["雪岳洞入口に到着＋ドライバーガイドによるオリエンテーション（約10分）","統一大仏＋神興寺まで徒歩（メイン駐車場から約15〜20分）","オプション：権金城へのケーブルカー（待ち時間含む約30〜45分）または飛仙台への散策（約90分）","写真撮影＋車両への集合（約15分）","オプション：神興寺近くの樹齢800年の松の木での写真撮影（約5分）"],"_poi_meta":{"poi_key":"seoraksan_national_park","verified":true,"match":"single_poi","kb_version":"1.27","verified_date":"2026-04-29","sources":["Korea Tourism Organization (VisitKorea — Seoraksan National Park (Outer Seorak) listing + IUCN Green List confirmation)","IUCN Green List of Protected and Conserved Areas (iucngreenlist.org — Seoraksan official entry + 2014 designation + 398.24 km² area)","Korea National Park Service (KNPS — Seoraksan National Park Office official site + endangered species management plan)","UNESCO World Heritage Centre (Mt. Sorak Biosphere Reserve 1982 designation + tentative World Heritage listing)","Wikipedia (Seoraksan National Park — corpus on 30 peaks, 2,000+ animal species, 1,400+ plant species)"]},"highlights":["韓国第5の国立公園(1970年)で唯一のユネスコ生物圏保存地域(1982年8月)","統一大仏: 14.6m / 108トン青銅 — 世界最大級の坐像青銅仏(1997年)","Replace 新興寺 → 神興寺 to match glossary and accurate Hanja.","オプション 雪岳山ロープウェイ1,132mで権金城プラットフォーム(700m、1253年伝説)","30峰、2,000以上の動物種、1,400~1,562の植物種、希少野生動物(ジャコウジカ、ゴーラル、ツキノワグマ)","公園入場料は2023年5月廃止で無料（以前3,500ウォン）、ロープウェイは引き続き有料","**2005年からIUCNカテゴリーII(国立公園)+2014年からIUCN保護地域グリーンリスト** — 五台山・智異山と並びパイロットフェーズで初めてグリーンリスト入りした韓国国立公園","**1982年8月から韓国唯一のユネスコ生物圏保存地域** + **ユネスコ世界遺産暫定リスト掲載** — 韓国の他の国立公園に類例のない複合認定","**ヒマラヤゴーラル保全の中核**: 約260頭の安定個体群(IUCNレッドリストで危急種) — 公園は絶滅危惧種のため特別保護区10カ所、計39km²(公園総面積の10%)を管理"],"smartNotes":{"photo":"統一大仏(14.6m青銅仏)が象徴的な単発ショット。ロープウェイから神興寺+蔚山岩+束草市街+東海を一望。10月の紅葉に映える花崗岩峰は世界的に有名。","facilities":"ビジターセンター、カフェ(ダヒャンカフェ)、レストラン、雪岳洞ゲートのギフトショップ。ハイキング用具の無料レンタル9:00~14:00(16:00までに返却)。入口にツキノワグマのマスコット像。","tip":"ロープウェイチケットは事前予約不可 — 10月は1~2時間以上の行列も。霧の日はロープウェイをパス(視界ゼロ)。3時間ベスト配分: 統一大仏+神興寺+飛仙台渓流散策。歩道は岩がちで湿っている箇所もあるためしっかりしたつま先閉じの靴を。"},"whyOnRoute":"片道2.5時間のドライブを正当化するのは、その中心: 韓国第5の国立公園(1970年)であり、韓国唯一のユネスコ生物圏保存地域(1982年) — 加えて世界最大級の坐像青銅仏と世界最古の禅仏教寺院が、すべて小公園入口から徒歩15分以内に集積しています。落山寺の代替案より優先する理由は、雪岳洞ゲートが舗装された神興寺+ロープウェイ尾根アクセス+飛仙台渓流トレイルを単一の3時間枠に収め、これだけ短い歩行予算で3要素すべてを組み合わせる雪岳山立ち寄り先は他にないこと。雪岳山のIUCNグリーンリスト+ユネスコ生物圏保存地域+世界遺産暫定リスト掲載の組み合わせは、**韓国で最も認知された自然遺産公園**としての地位を確立 — 5時間の往復ドライブコストを、純粋な景観の代替案(五台山、智異山)では実現できない方法で正当化する初訪韓トラベラー向けの単一山岳アンカー資格となります。","convenience":{"restroom":"Glossary ''Sinheungsa Temple'' → 神興寺. Translator used WRONG kanji 新興寺 (新 = new) instead of correct 神興寺 (神 = god, matches Korean Hanja 神興). Replace 新興寺 → 神興寺 across all 3 occurrences.","parking":"小公園メインゲートに駐車場(有料)"},"description":"**雪岳山**は**韓国第5の国立公園**で1970年3月に指定、1982年8月にはその卓越した山岳生物多様性によりユネスコ生物圏保存地域として認定された、**韓国唯一の同認定地**です。公園は4市郡にまたがる約398km²、30の名峰を擁し、最高峰は**大青峰(1,708m、韓国第3位)**、有名な**蔚山岩(ウルサンバウィ)**の6本柱の花崗岩岩塊もここにあります。公園入場料は無料 — **神興寺**に代わって徴収されていた3,500ウォンの料金が2023年5月に廃止されました(現在は公的資金で寺院を維持)。\n\n小公園(外雪岳)メインゲートからの典型的な3時間訪問は3つのハイライトを網羅します: **統一大仏**(高さ14.6m、108トンの青銅で世界最大級の坐像青銅仏、1997年に韓国統一を祈念して建立、内部に観音菩薩堂)、神興寺(西暦652年に新羅時代の慈蔵律師が創建した世界最古の禅(ソン)寺院で曹渓宗の総本山)、オプションの**雪岳山ロープウェイ**(片道約10分、1,132mで標高700mの権金城プラットフォームへ — **大人往復16,000ウォン / 子ども12,000ウォン**、現地販売のみで予約不可、10月の紅葉ピーク時は数時間待ちもあり)。\n\n山頂の権金城には鮮やかな伝説 — 1253年のモンゴル軍による高麗侵攻時、権・金という2人の将軍が一日で築いたとされる名前の由来があります。ロープウェイを使わない健脚派には、1.5kmの飛仙台渓流脇散策(ほぼ舗装路)、揺れ岩のループ(片道1.5時間、石段あり)、600mの金剛窟洞窟登り(往復約1時間40分)などのコースもあります。","visitBasics":{"hours":"公園は常時開放、ロープウェイは通常8:00~17:30(天候次第)、神興寺は6:00~日没","closed":"通年開園、一部トレイルが復元のため期間休止することあり","admission":"公園入場無料（以前は3,500ウォン、2023年5月廃止）、ロープウェイ往復 大人16,000 / 子ども12,000ウォン（現地販売のみ、事前予約不可）","walking":"麓は易しい(神興寺、ロープウェイ駅)、中~高難易度のハイキング(飛仙台3km、蔚山岩の急階段、揺れ岩は片道1.5時間)"},"image":"/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp","images":["/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp","/images/tours/seoraksan-national-park/seoraksan-sinheungsa-ulsanbawi.webp","/images/tours/seoraksan-national-park/photo-001.webp"]},{"name":"南怡島（ナミソム）","time":"≈ 14:30","number":3,"category":"加平郡の河中島 — 「冬のソナタ」ロケ地・ポプラ並木","duration":"120分（2時間）","timeUsed":["加平桟橋からフェリーで渡る（待ち時間含む5〜10分）","メタセコイア／イチョウ／チョウセンゴヨウの並木道を自由散策 — 島の半周コース約3km","オプション：自転車レンタル（シングル7,000ウォン／タンデム14,000ウォン、1時間あたり）または電気式ブルートレイン（ユニセフホールまで片道3,000ウォン）","島内での軽食休憩（ソナタカフェ、ホットク、さつまいもラテ）","本土へ戻るフェリーに乗船"],"_poi_meta":{"poi_key":"nami_island","verified":true,"match":"single_poi","kb_version":"1.27","verified_date":"2026-04-29","sources":["Korea Tourism Organization (VisitKorea — Nami Island official listing + visa fee schedule)","Naminara Republic Official Site (namisum-en.imweb.me — own corpus on cultural-independence brand)","UNICEF Korea (Nami Island 2010 Child Friendly Park designation + International Children''s Book Festival)","KBS / Korea Times (Winter Sonata 2002 production retrospectives + Japanese tourism boom coverage)","Wikipedia (Namiseom — open corpus on General Nami history + Cheongpyeong Dam 1944 origin)"]},"highlights":["**「冬のソナタ」（2002年）**のロケ地 — 東アジアKドラマ聖地","**メタセコイア・ポプラ並木** — 秋の黄金色の落葉が絶景","春：菜の花畑。夏：緑のトンネル。秋：紅葉。冬：雪景色 — **4シーズン対応**","加平港からフェリーで5〜10分（**フェリー代金含まれます**）","年間約**200万人**が訪れる東アジアのKドラマ観光地"],"smartNotes":{"photo":"メタセコイア並木 — 秋の黄金色と冬の雪景色が代表的なショット。","facilities":"島内に韓屋風レストラン、カフェ、お土産店。","tip":"ベストシーズン：春（4〜5月桜）、秋（10月黄金のイチョウ）。週末ピーク時は早めの到着を。"},"whyOnRoute":"南怡島を最初に配置することで、並木道の写真撮影に最も強い朝の光を活用します。","convenience":{"restroom":"島内複数か所＋カピョン桟橋","parking":"カピョン桟橋 小型車₩6,000/大型車₩10,000"},"description":"**南怡島**は京畿道加平郡の北漢江に浮かぶ**半月形の河中島（周囲4.6km）**で、**朝鮮王朝第7代王の庶子・南怡将軍**にちなんで名付けられた。1965年に春川ダム建設で生まれた人工島。日本での「**冬のソナタ****」（2002年、KBS）の爆発的ヒット**以降、東アジアのKドラマツーリズムの聖地として知られ、韓国国内外から年間**約200万人**が訪れる。\n\n最も有名な景観は**メタセコイアのポプラ並木** — 秋の黄金色の落葉が絶景。また、** （ロシアオリーブ）の並木**・**（菜の花）畑**・**（コスモス）畑**など、季節ごとに異なる絵画的な風景が島内各所に広がります。島内を自転車で回ることも可能（レンタル有料）。加平港からフェリーで5〜10分（フェリー代金はツアーに含まれます）。","visitBasics":{"hours":"島 08:00〜21:00（最終フェリーは変動）。島内の店舗は主に18:00閉店","closed":"年中無休","admission":"ナミナラ共和国VISAフィー（往復フェリー込み）：通常₩19,000 / 割引₩13,000","walking":"楽 — 平坦な並木道。全周約5km。自転車/電動バギーレンタルあり"},"image":"/images/tours/nami-island/kakaotalk-20260510-222949305-04.webp","images":["/images/tours/nami-island/kakaotalk-20260510-222949305-04.webp","/images/tours/nami-island/kakaotalk-20260510-222949305-05.webp","/images/tours/nami-island/chatgpt-image-2026-5-11-01-12-05.webp","/images/tours/nami-island/nami-metasequoia-sunset-lake.webp"],"imageCredits":[{"url":"/images/tours/nami-island/kakaotalk-20260510-222949305-04.webp","source":"atoc-korea"},{"url":"/images/tours/nami-island/kakaotalk-20260510-222949305-05.webp","source":"atoc-korea"},{"url":"/images/tours/nami-island/chatgpt-image-2026-5-11-01-12-05.webp","source":"atoc-korea"},{"url":"/images/tours/nami-island/nami-metasequoia-sunset-lake.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/nami-island/kakaotalk-20260510-222949305-04.webp","location":"南怡島（ナミソム）","caption":"南怡島（ナミソム） — photo 1","alt":"南怡島（ナミソム） — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/nami-island/kakaotalk-20260510-222949305-05.webp","location":"南怡島（ナミソム）","caption":"南怡島（ナミソム） — photo 2","alt":"南怡島（ナミソム） — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/nami-island/chatgpt-image-2026-5-11-01-12-05.webp","location":"南怡島（ナミソム）","caption":"南怡島（ナミソム） — photo 3","alt":"南怡島（ナミソム） — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/nami-island/nami-metasequoia-sunset-lake.webp","location":"南怡島（ナミソム）","caption":"南怡島（ナミソム） — photo 6","alt":"南怡島（ナミソム） — gallery image 6"}]},{"name":"晨靜苑","time":"≈ 17:00","number":4,"category":"「朝の静けさ」の庭園 — 10万平米の植物園・加平郡","duration":"70分","timeUsed":["ドライバーガイドによる庭園入場と簡単なオリエンテーション（約5分）","20のテーマ別サブガーデンを自由に散策（約50分）","オプション：サンクンガーデン（朝鮮半島の形）での撮影延長時間（約10分）","冬季訪問：昼間の庭園とライトアップ点灯式の両方をお楽しみいただけるよう、イルミネーション開始時刻の17:00に合わせて到着","コーチ（バス）に集合（約5分）"],"_poi_meta":{"poi_key":"garden_of_morning_calm","verified":true,"match":"single_poi","kb_version":"1.27","verified_date":"2026-04-29","note":"POI verified in KB v1.10 (Batch 7) and reused here unchanged.","sources":["Garden of Morning Calm Official Site (morningcalm.co.kr — own corpus on founder + 1996 opening + 20 sub-gardens)","Korea Tourism Organization (VisitKorea — Lighting Festival listing + lighting-fest schedule)","Gyeonggi Cultural Foundation (ggc.ggcf.kr — official cultural promotion entry on Sunken Garden + 200,000 LEDs)","Sahmyook University Department of Horticulture (Prof. Han Sang-kyung honorary professor profile + garden origin)","Wikipedia (Garden of Morning Calm — corpus on Tagore-derived name + 5,000 species + 330,000 m² total)"]},"highlights":["韓国を代表する私設樹木園 — 330,000m²に約5,000種の植物","三育大学のハン・サンギョン氏が創設。1996年開園(構想は1992年)","冬期ライティング・フェスティバル 2025年12月5日〜2026年3月15日、30,000個以上のLED(韓国初の自然環境ライト・フェスティバル)","20のテーマ別小庭園 — 韓半島の形をした沈床園、ムーンライト・ガーデン、盆栽園、エデンの園","Glossary ''K-drama filming location'' → 韓国ドラマのロケ地. JA uses ''Kドラマのロケ地'' (loanword K). For consistency with glossary: ''複数の韓国ドラマのロケ地''. Note: corpus uses Kドラマ 26x vs 韓国ドラマ 2x — systemic. May be acceptable native usage; minor.","**1992年構想/1994年土地購入/1996年5月11日開園**:創設者ハン・サンギョン教授(三育大学園芸学科)と妻が全庭を自ら設計・栽培。初期の財政難期には自宅を売却","**CNN「韓国観光地トップ50」選出** — 沈床園の韓半島形(統一を願う10の大小花壇)がCNN指摘の象徴的特徴","**ライティング・フェスティバルでは20万個以上の環境配慮型LED電球**(12〜3月)を使用 — 韓国初の自然環境ライト・フェスティバル。日没17時頃から毎晩点灯","**チョンニョンヒャン(中国産イブキ)**が朝の静けさ樹木園の公式シンボル — 5,000種の中で園を代表する樹種"],"smartNotes":{"photo":"春(4月の桜)、夏(濃緑)、秋(10月〜11月初旬の紅葉)、冬(日没後のライトアップ)それぞれ異なる写真表現が可能。フェスティバル期間中の夕暮れの光のトンネルが象徴的なショット。","facilities":"「フードガーデン」では韓国の家庭料理(味噌チゲ、野菜ビビンバ、雪チーズトッポッキ)を提供。シグニチャーカフェは韓屋焙煎所の「Good Morning Coffee」。レストランは20:00閉店。","tip":"ライティング・フェスティバル(12月5日〜3月15日)は16時頃到着で日中の庭園を見たあと、点灯(17時頃〜)まで滞在を。2月の大雪は『アナと雪の女王』のような幻想的な景色を作ります。"},"whyOnRoute":"朝の静けさ樹木園を1日の中間に置くことで、南怡島の活発な散策コースとプチフランスのコンパクトな村の立ち寄りの間に、ルート最も穏やかな視覚チャプターが生まれます。12〜3月にはここが1日のハイライトとなり — ライティング・フェスティバルが17:00〜21:00のピークに突入する頃には、加平の他のスポットは営業を終え始めます。中間配置はまた、庭園の写真評価を支える**遷移する午後光**を捉えるためでもあり — 秋の14:00〜16:00の柔らかいサイドライトが楓の紅葉色を引き立て、冬には同じ時間帯がライティング・フェスティバルの17:00点灯と重なり、プライベート貸切のお客様は1回の入場料で実質2つの異なる視覚的庭園(日中の樹木園+夜のLEDフェスティバル)を体験できます。","convenience":{"restroom":"複数、案内表示あり","parking":"大型無料駐車場。コインロッカー1,500〜2,000 KRW(500ウォン硬貨のみ)"},"description":"南怡島から南へ約30分、朝の静けさ樹木園は韓国を代表する私設樹木園で、約330,000m²の整備された景観の中に約5,000種の植物が育まれています。1992年に構想、1996年に一般公開され、三育大学のハン・サンギョン教授が自ら設計・栽培を手がけました(資金不足の時期には自宅を売却して建設を続けた逸話も)。名称は韓国の古来の異名「朝鮮(朝の静けさの国)」に由来。\n\n20のテーマ別小庭園 — 韓半島の形をした「沈床園」、故郷の家ガーデン、盆栽園、ムーンライト・ガーデン、空の道、エデンの園など — それぞれが独自の視覚的アイデンティティを持ち、『雲が描いた月明り』をはじめ多数のKドラマのロケ地となっています。毎年12月初旬から3月中旬まで、韓国初の自然環境ライティング・フェスティバルを開催 — 2025〜2026年版は2025年12月5日〜2026年3月15日で、3万個以上のLEDが園内を覆い、日没後の庭園を冬のワンダーランドに変貌させます。\n\nフェスティバル期間の営業時間は日〜金 11:00〜21:00、土 11:00〜23:00。期間外は08:30〜19:00(最終入場18:00)で運営します。**「朝の静けさ樹木園」**の名は、1929年に韓国を「朝の静けさの国」と呼んだインドの詩人ラビンドラナート・タゴールに由来します。ハン・サンギョン教授は1992年、米国で交換教授を務めていた際に世界一流の私設庭園に触発され、本プロジェクトを構想。\n\n1994年に土地を購入 — もとは焼畑農業で開かれた荒れた石ころ地でした。**ハン氏夫妻が自ら設計・労働を行い**、財政難の時期には自宅を売却して敷地内の小屋に住み込みで建設を続けました。庭園は1996年5月11日に10のテーマセクションで初公開 — 現在は330,000m²に20のテーマ別庭園を擁するまでに拡張されています。","visitBasics":{"hours":"春〜秋 08:30〜19:00(最終入場18:00)。冬期ライティング・フェスティバル 日〜金 11:00〜21:00、土 11:00〜23:00","closed":"年中無休","admission":"大人 11,000 KRW / シニア65歳以上 9,000 KRW / 中高生(13-18歳) 8,500 KRW / 子供(3-12歳) 7,500 KRW(チケット保有者は隣接動物園2,000 KRW割引)","walking":"難易度:中 — 起伏のある地形を縫う20のテーマ別小庭園を巡る広範囲の遊歩道。主要ループの大半はベビーカー対応"},"image":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-36-31.webp","images":["/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-36-31.webp","/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-43-58.webp","/images/tours/garden-of-morning-calm/garden-of-morning-calm-flowers.webp","/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-11-01-09-33.webp"],"imageCredits":[{"url":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-36-31.webp","source":"atoc-korea"},{"url":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-43-58.webp","source":"atoc-korea"},{"url":"/images/tours/garden-of-morning-calm/garden-of-morning-calm-flowers.webp","source":"atoc-korea"},{"url":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-11-01-09-33.webp","source":"atoc-korea"},{"url":"/images/tours/garden-of-morning-calm/garden-of-morning-calm-flowers.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-36-31.webp","location":"晨靜苑","caption":"晨靜苑 — photo 1","alt":"晨靜苑 — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-43-58.webp","location":"晨靜苑","caption":"晨靜苑 — photo 2","alt":"晨靜苑 — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/garden-of-morning-calm/garden-of-morning-calm-flowers.webp","location":"晨靜苑","caption":"晨靜苑 — photo 3","alt":"晨靜苑 — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-11-01-09-33.webp","location":"晨靜苑","caption":"晨靜苑 — photo 4","alt":"晨靜苑 — gallery image 4"}]},{"name":"ソウルへ帰着（弘益大学駅または明洞駅）","time":"≈ 19:00","number":5,"category":"帰りの降車","duration":"車で60分","timeUsed":["コーチ（バス）がモーニングカームを出発（約18:10）","ソウル양양（ソウル・ヤンヤン）高速道路経由でソウルへ（交通状況により約60分）","明洞駅2番出口で降車（約19:00）","弘益大学駅8番出口で降車（約19:30）"],"whyOnRoute":"帰りはピックアップの逆順となります：ソウル・ヤンヤン高速道路経由でモーニングカームに近い**明洞が先に降車**（約19:00）、次に**弘益大学駅で降車**（約19:30）。ツアーの所要時間13時間はこの明洞到着時刻を基準に設定されています。夜に夕食のご予約がある方は、交通渋滞を考慮し20:00以降のご予約をお勧めします。金曜・日曜の夜は高速道路が混雑し、帰着が30分程度遅れる場合があります。フライトや重要なご予定がある方は、事前にドライバーガイドへお知らせください。","description":"After Morning Calm, the coach takes the **Seoul-Yangyang Expressway** westbound back into Seoul. Drop-offs are sequenced: **Myeongdong Station Exit 2 first at approximately 19:00**, then **Hongik University Station Exit 8 at approximately 19:30**. Both drop-off points are at the same locations as morning pickup. \n\nGuests connecting to evening shows in Hongdae or dinner reservations in Myeongdong should plan for **20:00 or later** to allow a comfortable buffer for traffic, particularly on Friday and Sunday evenings when the expressway runs heavier."}],"routeFlowStops":[{"name":"ピックアップ（弘大 / 明洞）","type":"origin","theme":"ソウルピックアップ"},{"name":"雪岳山国立公園","type":"primary","theme":"山と寺院"},{"name":"ナミ島","type":"primary","theme":"K-ドラマの島"},{"name":"朝の静寂の庭園（アチムコヨ樹木院）","type":"primary","theme":"テーマガーデン"},{"name":"ソウルへ戻る","type":"return","theme":"解散・降車"}],"routePhases":[{"phase":"ソウル → 雪岳山（ソラクサン）","duration":"約3時間","description":"ホンイク06:00・明洞06:30にピックアップ後、ソウル-ヤンヤン高速道路を北東へ約2時間30分走り、10:00までに雪岳山に到着。"},{"phase":"雪岳山（ソラクサン）","duration":"約3時間","description":"ソゴンウォン入口：統一大仏、神興寺を見学し、オプションで権金城へのロープウェイ乗車または飛仙台沿いの渓流散策。"},{"phase":"雪岳山 → 南怡島（ナミソム）（昼食込み）","duration":"約2時間30分","description":"インジェ-ホンチョン-春川ルートを南下。途中、江原道の地元レストランで昼食（各自負担）。"},{"phase":"南怡島（ナミソム）","duration":"約2時間","description":"ナミナラ共和国でのフェリー往復と、メタセコイア・イチョウ・韓国松の並木道ウォーキングコース。"},{"phase":"朝の静寂の庭園と帰路","duration":"約2時間","description":"南へ車で約30分、朝の静寂の庭園へ（滞在70分）。その後ソウル-ヤンヤン高速道路を経由して約1時間でソウルに帰着。"}],"routeShapeIntro":{"title":"このソウル発1日ツアーの流れ","subtitle":"ホンイク/明洞を06:00/06:30に出発し、北東へ約2時間30分かけて雪岳山へ（当日のメイン山岳スポット）。インジェ-春川ルートを通り、南怡島の並木道フェリーコースへ。さらに南へ30分で朝の静寂の庭園へ（冬はイルミネーションフェスティバルの点灯あり）、1日の穏やかなフィナーレを飾る。19:00〜19:30にソウルへ帰着。"},"whyTourWorks":{"bestFor":["韓国の代表的な日帰りスポット3か所を1日で制覇したい初訪問者","「冬のソナタ」のメタセコイア並木を目当てに訪れるカップルや韓流ファン","山・島・庭園の三拍子を求めるフォトグラファー・写真愛好家","ソウルを拠点に最大限の観光を楽しみたい、13時間の行程もいとわない旅行者"],"lessIdealFor":["ゆったりとした一箇所のみの体験を希望する旅行者","06:00出発の13時間行程に参加したくないゲスト","長時間のバス移動が辛い可能性のある幼いお子様（6歳未満）","移動に制限のある旅行者 — 雪岳山の道には階段や岩場があります"],"routeLogicSections":[{"title":"ペース配分と地理","icon":"sun","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"まず北東へ、帰りは西へ","detail":"雪岳山は最も遠い目的地（片道約2.5時間）のため、エネルギーが最も充実している最初に訪問します。南怡島とモーニングカームは、春川・加平回廊を通る自然な帰路に沿って組み込まれており、引き返しは一切ありません。"},{"label":"山 → 島 → 庭園","detail":"一日の流れは、最もエネルギーを要する活動（雪岳山の階段とオプションのケーブルカー）から中程度（南怡島の平坦な散策コース）、そして最もゆったりとした活動（モーニングカームのリラックスした庭園散歩）へと移ります。写真のスタイルも、花崗岩の尾根 → 並木道 → 精選された植物の構図へと変化していきます。"},{"label":"冬限定のスペシャルボーナス","detail":"12月5日〜3月15日の期間中、17:00のモーニングカーム到着で昼間の庭園とイルミネーションフェスティバルの点灯を両方楽しめます — 330,000㎡の敷地に20万個以上のLEDが輝くこの体験を、個人旅行者がこれほど完璧なタイミングで実現するのは容易ではありません。"}]},{"title":"なぜ13時間でこれが成り立つのか","icon":"clock","iconBg":"bg-pink-50/80","iconColor":"text-pink-600","items":[{"label":"すべての入場料込み","detail":"南怡島のフェリー（₩19,000）とモーニングカームの庭園（₩11,000）はツアー料金に含まれており、各スポットでのチケット購入は不要です。オプションの雪岳ケーブルカー（往復₩16,000）のみ現地での自己負担となります。"},{"label":"ソウル全域の2つの乗車ポイント","detail":"弘大（麻浦区）06:00発と明洞（中区）06:30発の2箇所が、ソウルの2大宿泊エリアをカバーしています — ゲストはご自身のホテルに最も近い出発地点をお選びください。"},{"label":"ほぼすべて屋外スポット","detail":"3つのスポットはいずれも主に屋外です。バスのみが唯一の屋内区間となります。穏やかな天候では快適に楽しめますが、大雨の場合はケーブルカーが利用不可となることがあります。それ以外のすべての観光は引き続きお楽しみいただけます。"}]},{"title":"正直なトレードオフ","icon":"info","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"雪岳山には階段があります（ケーブルカーはオプション）","detail":"神興寺境内のルートおよびオプションの흔들바위（ヒュンドゥルバウィ）周回コースには、いずれも階段があります。統一大仏＋神興寺の散策路は平坦でアクセスしやすく、ケーブルカーはチェアリフト式（ケーブルカー自体に階段はありません）ですが、権金城のプラットフォームには頂上付近に岩の段差があります。"},{"label":"ケーブルカーは事前予約不可","detail":"雪岳ケーブルカーのチケットは現地販売のみで、10月のピーク時は1〜2時間並ぶ場合があります。空が霧がかっていたり行列が長い場合は、飛仙台（ビソンデ）沿渓ウォーク（平坦・舗装済み、往復約90分）をおすすめします。同じ3時間の予算内に収まります。"},{"label":"06:00出発の長い一日","detail":"これはコーチグループツアーです。コーチ移動時間約4.5時間を含む合計13時間のツアーです。時間を短縮したい方や自由な滞在時間をご希望の方は、プライベートチャーター車の日帰りツアー（ホテル玄関送迎・時間カスタマイズ可）をご検討ください。"}]}]},"practicalAccordionItems":[{"id":"pickup","title":"乗車・降車場所","preview":"ソウルの乗車地点は2か所：弘大入口駅8番出口スターバックス（06:00）…","content":["ソウルの乗車地点は2か所：**弘大入口駅8番出口スターバックス（06:00）**（麻浦区）と、**明洞駅2番出口（ノースフェイス旗艦店）（06:30）**（中区）。","両乗車地点は同じコーチを共有します。選択した乗車地点に5分前までにお集まりください。","帰りの降車は逆順：**明洞 約19:00、弘大 約19:30**。","金曜・日曜の夜は高速道路の渋滞により30分程度遅れる場合があります。スケジュールに余裕がない場合はガイドにお知らせください。"]},{"id":"what-to-bring","title":"服装と持ち物","preview":"雪岳山の登山道（一部に岩場あり）に適した、つま先が覆われた歩きやすい靴…","content":["雪岳山の登山道（一部に岩場あり）に適した、つま先が覆われた歩きやすい靴。","10月〜3月は重ね着をお勧めします。雪岳山は標高が高いため、ソウルより5〜7°C気温が低くなります。","カメラまたはスマートフォン（南怡島のメタセコイア並木と晨靜樹木園が写真スポットのハイライトです）。","昼食（約₩10,000〜15,000）と、乗車をご予定の方は雪岳ケーブルカー（₩16,000）のために現金またはカードをご準備ください。","朝食なしで出発される場合は軽食をご持参ください。最初の食事休憩は南怡島への途中、13:00〜13:30頃です。"]},{"id":"weather-policy","title":"天候について","preview":"年間を通じて運行します。","content":["年間を通じて運行します。","小雨の場合：ツアーは予定通り実施します。南怡島と晨靜樹木園は雨でも趣があり、雪岳山の低地の登山道はグリップ力のある靴があれば歩行可能です。","大雨の場合：嵐の状況では雪岳ケーブルカーは通常運休となります（事前支払い分は払い戻し）。ガイドは代わりに飛仙台ウォークまたは神興寺の延長見学にご案内します。","台風レベルの悪天候または高速道路閉鎖の場合：全額払い戻しまたは予約変更が可能です。"]},{"id":"inclusions","title":"含まれるもの","preview":"ソウル2か所からの送迎、大型コーチ、英語ガイド、南怡島および晨靜樹木園の入場料…","content":["ソウル2か所の乗降地点、空調完備の大型コーチ、有資格英語ガイド。","**ナミ島フェリー往復 ＋ ナミナラ共和国VISAフィー（₩19,000）— 料金に含まれます**。","**モーニングカームガーデン入場料（₩11,000）— 料金に含まれます**。","**雪岳山（ソラクサン）国立公園入場料 — 無料（2023年5月廃止）**。","**含まれないもの**：途中の昼食（約₩10,000〜15,000）、任意の雪岳ケーブルカー（₩16,000往復、現地チケット購入のみ）。"]},{"id":"language","title":"言語","preview":"メインのツアー言語：英語。","content":["メインのツアー言語：英語。","中国語対応ガイドはリクエストにより手配可能 — 3日以上前にご予約ください。","メニュー・看板・屋台でのやり取りには韓国語が使用されますが、ガイドが通訳いたします。"]},{"id":"walking","title":"徒歩と地形","preview":"中程度。","content":["中程度。","雪岳山：新興寺（シネウンサ）周辺は楽；飛仙台（ビソンデ）ウォークは中程度；흔들바위（ヘウンドゥルバウィ）や울산바위（ウルサンバウィ）を選ぶ場合は階段があり難度高め。","ナミ島：平坦な舗装された並木道；約3kmを2時間かけて歩くのが一般的なペースです。","モーニングカーム：緩やかな起伏のある地形で、ほぼ舗装されたガーデンパスが続きます。","合計歩行距離 約4〜5km ＋ 任意の雪岳山の階段。","ベビーカーはナミ島とモーニングカームの一部で利用可能；雪岳山の上部トレイルでは不可。"]},{"id":"lunch","title":"昼食（各自負担）","preview":"昼食は雪岳山からナミ島への移動途中、13:30頃に…","content":["昼食は雪岳山からナミ島への移動途中、13:30頃にインジェ〜春川（チュンチョン）回廊沿いの地元レストランでお取りいただきます。","定番メニュー：春川ダッカルビ（地域で最も有名な料理 — キャベツとトッポギを加えた甘辛炒め鶏肉）、カルグクス（手打ち麺スープ）、ビビンバ（約₩10,000〜15,000）。","事前にご連絡いただければ、ベジタリアンおよびハラール対応が可能です — ご予約時にお知らせください。"]},{"id":"cancellation","title":"キャンセル","preview":"ピックアップの24時間前まで無料でキャンセル可能です。","content":["ピックアップの24時間前まで無料でキャンセル可能です。","24時間以内のキャンセル：50%返金。","無断キャンセルまたはピックアップの見逃し：返金不可 — ただし、ピックアップ予定時刻から10分以内にAtoC Korea運営部門へご連絡いただければ、バスが予定より早く進んでいる場合は少々お待ちいただける場合があります。"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"季節のご案内をご参照ください"},"tomorrow":{"temp":"—","label":"季節のご案内をご参照ください"},"_seasonalSummary":"Seoul + Gangwon: temperate four-season climate. Seoraksan is 5-7°C cooler than Seoul year-round. Hot humid summers (Jun-Aug), crisp cold winters (Dec-Feb), with prime seasons in spring (April cherry blossoms) and autumn (October-November foliage)."},"seasonalVariations":[{"season":"春（3月〜5月）","description":"4月上旬〜中旬には南怡島とモーニングカームで桜が開花。4月下旬には雪嶽山でツツジとレンギョウが見頃を迎えます。長時間のバス旅に最も快適な気候です。"},{"season":"夏（6月〜8月）","description":"雪嶽山のトレイルは鮮やかな緑に包まれ、南怡島の並木道は木陰が最高潮に。7月の梅雨により雪嶽山の滞在時間が短縮される場合があります。モーニングカームの紫陽花とバラは6月が見頃です。"},{"season":"秋（9月〜11月）","description":"韓国を代表する季節 — 10月中旬から11月上旬の雪嶽山の紅葉は世界的に有名。10月下旬〜11月には南怡島のイチョウとメタセコイアが黄金色に染まり、10月にはモーニングカームの菊とモミジが見頃を迎えます。最も需要が高い季節のため、2週間以上前のご予約をおすすめします。"},{"season":"冬（12月〜2月）","description":"**冬はこのツアーの象徴的な「ウィンターワンダー」シーズンです**：花崗岩の峰々に雪が積もる雪嶽山、雪化粧したメタセコイア並木が「冬のソナタ」の世界観を呼び起こす南怡島、そしてモーニングカームのウィンターライティングフェスティバル（12月5日〜3月15日）では庭園全体に20万個以上のLEDが灯ります — ツアーの17:00到着で、日中の庭園美とイルミネーション点灯の瞬間の両方をお楽しみいただけます。"}],"bookingTrustItems":[{"icon":"check-circle","title":"入場料すべて込み","description":"南怡島フェリー＋モーニングカームがセット","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600","body":"南怡島フェリー（₩19,000）とモーニングカーム（₩11,000）の入場料はツアー料金に含まれており、各スポットでのチケット購入は不要です。雪嶽山の入場料は無料（2023年5月廃止）。入場料の総節約額：約₩30,000。"},{"icon":"users","title":"公認英語ガイド付き","description":"韓国公認ツアーガイド","iconBg":"bg-pink-50/80","iconColor":"text-pink-600","body":"韓国観光公社認定の英語堪能なガイドが案内します。中国語対応ガイドは事前リクエストにて手配可能です。ガイドによる解説では、雪嶽山の新羅時代の寺院の歴史、南怡島の「冬のソナタ」にまつわる背景、そしてモーニングカームの創設者のストーリーをご紹介します。"},{"icon":"shield","title":"明瞭な料金体系","description":"隠れたショッピングストップなし","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","body":"高麗人参店への立ち寄りなし、免税店なし、コミッション目的のお土産店への寄り道なし。13時間の終日ツアーのすべての時間は、観光地での滞在か移動に充てられます。予約したとおりのご体験をお届けします。"}],"bookingSupportSteps":[{"timing":"即時","title":"即時確認","detail":"ピックアップ場所選択付き予約確認","description":"弘大（ホンデ）・明洞のピックアップ場所選択付き即時予約確認。"},{"timing":"前日","title":"ピックアップ詳細","detail":"WhatsApp／SMSにて正確なピックアップ場所と車両情報をお知らせ","description":"天気確認、コーチのナンバープレート、季節ごとのルートに関する注意事項（アチムコヨ樹木園ライティングフェスティバルの時間、雪岳山の紅葉ピーク時期など）を前日にお送りします。"},{"timing":"当日朝","title":"ピックアップ確認","detail":"出発10分前にピックアップ場所でガイドが確認対応","description":"ガイドは05:50よりスターバックス弘大8番出口前、06:20より明洞2番出口（ノースフェイス前）にてお待ちします。前夜にガイドとコーチの写真をWhatsAppへお送りします。"},{"timing":"ツアー中","title":"ツアー中サポート","detail":"各スポットでのガイドナレーション＋24時間対応オペレーションサポート","description":"ガイドは現地にて解説を行います。雪岳山の西暦652年・新羅時代の開創、ナミ島の1944年・清平ダム建設を起源とする歴史と2002年の「冬のソナタ」の舞台としての遺産、そしてアチムコヨ樹木園の1992年の構想と1996年の開園についてご説明します。"},{"timing":"終日の終わりに","title":"2か所の降車地点","detail":"明洞 約19:00 ／ 弘大 約19:30","description":"コーチは帰路、両ピックアップ地点に逆順で停車します。"},{"timing":"ツアー後","title":"レビュー＆フォローアップ","detail":"任意のツアー後レビュー","description":"ツアー後のフィードバックのお願いをお送りします。ソウル滞在中のレストランや観光スポットに関するご質問には当日中にお答えします。"}],"staticQuestions":[{"id":"duration","question":"このツアーはどのくらいの時間がかかりますか？","answer":"弘益大学駅06:00発、または明洞06:30発で、ドア・ツー・ドア13時間のツアーです。ソウルへの帰着は明洞が19:00頃、弘益大学駅が19:30頃となります。"},{"id":"pickup","question":"ピックアップ場所はどこですか？","answer":"ピックアップ場所は2か所あります。①**スターバックス 弘益大学駅8番出口**（麻浦区）06:00発 — 出口を上がってすぐのスターバックス、②**明洞駅2番出口**（中区）06:30発 — 出口を上がってすぐのノースフェイス旗艦店。ご予約の際、ホテルに近い方をお選びください。"},{"id":"drop-off","question":"降車場所はどこですか？","answer":"降車は同じ2か所に逆順で行います。まず明洞2番出口が19:00頃、次に弘益大学駅8番出口が19:30頃です。金曜・日曜の夜は高速道路の渋滞により、30分程度遅れる場合があります。"},{"id":"admissions","question":"入場料は含まれていますか？","answer":"有料施設2か所については含まれています。**南怡島フェリー往復（₩19,000）とア침고요樹木園（朝の静けさ）の入場料（₩11,000）は料金に含まれています**。**雪岳山国立公園の入場は無料**です（以前の₩3,500の入場料は2023年5月に廃止されました）。**唯一の有料オプションは雪岳山ケーブルカー**（往復₩16,000）で、現地購入のみ・自己負担となります。"},{"id":"cable-car","question":"雪岳山のケーブルカーには乗るべきですか？","answer":"晴天時には素晴らしい山稜の眺めが楽しめますが、チケットは事前予約不可で、10月の紅葉ピーク時には現地の待ち時間が1〜2時間を超えることもあります。霧がかかっている場合は景色が見えないため、乗車をお勧めしません。代わりに**飛仙台（ビソンデ）渓流沿いの散策**（舗装路1.5km、入口から往復約90分）がおすすめで、雪岳山での3時間をちょうど使い切れます。"},{"id":"winter-sonata","question":"南怡島は「冬のソナタ」のロケ地ですか？","answer":"はい。南怡島のメタセコイア並木道は、2002年のKBSドラマ「冬のソナタ」（ペ・ヨンジュンとチェ・ジウ主演）の代表的なロケ地です。並木道はどの季節も絵になりますが、秋（黄金色に輝く10〜11月）と冬（雪景色）が特に印象的です。"},{"id":"lighting-festival","question":"朝の静けさライトアップフェスティバルは見られますか？","answer":"**12月5日〜3月15日**の間にご予約いただければ見られます。ツアーは17:00に朝の静けさ樹木園に到着するため、昼間の庭園とライトアップ点灯の両方をお楽しみいただけます。フェスティバル期間外（4〜11月）は、季節の花々（4月の桜、6月のアジサイ、10月の紅葉）が楽しめる、のんびりとした植物園の時間となります。"},{"id":"kids","question":"このツアーは子どもでも参加できますか？","answer":"はい、6歳以上からご参加いただけます。06:00出発の13時間という長丁場は幼い子どもには負担が大きいため、快適にお楽しみいただくには8歳以上をお勧めします。子どもは南怡島のクジャクや「セコイアブリッジ」、冬の朝の静けさのライトアップを特に楽しめるでしょう。雪岳山の遊歩道には岩場もありますが、神興寺とケーブルカーは子ども連れでも安心です。"},{"id":"seniors","question":"シニアの方でも参加できますか？","answer":"アクティブなシニアの方であれば問題ありません。メインの体力的な負担は、南怡島と朝の静けさでの各2〜3kmの散策（いずれも平坦または緩やかな起伏）です。雪岳山では神興寺レベルまでは無理なく歩けます。「揺れ岩（フンドゥルバウィ）」周回コースには階段があるため、こちらはスキップ可能です。移動に制限のある方には、プライベート貸切車によるデイトリップをお勧めします。"},{"id":"lunch","question":"昼食は含まれていますか？","answer":"いいえ、昼食はお客様のご負担となります（目安：お一人様₩10,000〜15,000程度）。13:30頃、雪岳山から南怡島へ向かう途中、江原道の地元レストランに立ち寄ります。代表的なメニューは、**春川ダッカルビ**（鶏肉とキャベツ・餅を甘辛く炒めた料理）、**カルグクス**（手打ち麺スープ）、またはビビンバです。ベジタリアンやハラール対応は、事前にご連絡いただければ可能です。"},{"id":"language","question":"ガイドはどの言語に対応していますか？","answer":"主に英語対応です。中国語ガイドはリクエストに応じてご手配可能です（3日以上前にご予約ください）。ガイドは一日を通じてメニューの翻訳や屋台でのやり取りもサポートします。"},{"id":"best-season","question":"このツアーに最適な季節はいつですか？","answer":"**秋（10月中旬〜11月上旬）**は韓国を代表する紅葉シーズンです。雪岳山の紅葉は世界的に有名で、南怡島のイチョウ・モミジの並木道も黄金色に染まります。**冬（12月〜3月）**は、雪の雪岳山、南怡島の「冬のソナタ」の雰囲気、そして朝の静けさのライトアップフェスティバルが楽しめる「ウィンターワンダー」シーズンです。**春（4月）**は南怡島と朝の静けさで桜が咲き誇ります。10月のご予約は2週間以上前をお勧めします。"},{"id":"rain","question":"雨の場合はどうなりますか？","answer":"小雨の場合：ツアーは予定通り実施されます。適切な履き物があれば、3か所すべて雨の中でも徒歩で周ることができます。大雨の場合：雪嶽山ケーブルカーは通常運休となります（ガイドはビソンデ散策に切り替えます）。ナミ島とモーニングカームは通常通り営業しています。台風レベルの天候または高速道路の閉鎖の場合：全額返金または再予約が可能です。"},{"id":"private","question":"プライベートチャーターツアーとの違いは何ですか？","answer":"こちらはバジェット価格帯（お一人様59ドル）の観光バスグループツアーです。**プライベート貸し切り車日帰りツアー**オプションでは、ホテルのドアまでの送迎、柔軟な時間設定、カスタマイズ可能なルート（例：プチフランスの追加や雪嶽山の除外など）、プライベート車両をご利用いただけます。4名グループで通常300〜450ドルで、5名以上になると一人あたりの費用が同程度になります。予算重視の方は観光バスツアー、柔軟性と快適さを重視する方はプライベートツアーをお選びください。"},{"id":"walking","question":"どのくらい歩きますか？","answer":"3か所合計で約4〜5kmです。そのルートを選択した場合は、雪嶽山ケーブルカーのプラットフォーム階段（任意）も加わります。雪嶽山の道は湿っていたり岩場になっている箇所もあるため、つま先の閉じた丈夫な靴をお勧めします。"}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"pickup_dropoff":{"primary":{"name":"スターバックス 弘大入口駅 8番出口","address":"ソウル市麻浦区楊花路（弘大入口駅8番出口のスターバックス前）","time":"06:00 pickup / 19:30 drop-off","instructions":"弘大入口駅8番出口を上がってすぐのスターバックス店頭でガイドと合流してください。AtoC Koreaのサインと、ピックアップレーンに停車している大型観光バスを目印にしてください。"},"alternates":[{"name":"明洞駅 2番出口（ノースフェイス旗艦店）","address":"ソウル市中区退渓路（明洞駅2番出口のノースフェイス旗艦店）","time":"06:30 pickup / 19:00 drop-off","instructions":"明洞駅2番出口を上がったところにあるノースフェイス旗艦店前でガイドと合流してください。"}]},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"seoul-seoraksan-nami-island-morning-calm-day-tour","product_type":"bus","route_type":"fixed_route","destination_region":"seoul_gangwon","region_type":"gangwon_seoraksan","vehicle_type":"lar