  '',
  'USD',
  'person',
  '{"document_kind":"tour_product_full_page_v1","schema_version":7,"slug":"seoul-seoraksan-nami-island-morning-calm-day-tour","locale":"zh","product_id":"seoul-seoraksan-nami-island-morning-calm-day-tour","seo":{"pageTitle":"首尔一日游：雪岳山、南怡岛与晨静园 | AtoC Korea","metaDescription":"从首尔出发的13小时大巴一日游：雪岳山国立公园（UNESCO生物圈保护区）、南怡岛（《冬季恋歌》取景地）与晨静园——全程门票已含。","primaryKeywords":["首尔雪岳山一日游","南怡岛一日游","晨静园游览","雪岳山南怡岛一日游"],"ogImage":"https://www.atockorea.com/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp","title":"首尔一日游 · 雪岳山 + 南怡岛 + 晨静园 | AtoC Korea","description":"从首尔出发的大巴一日游，游览韩国最负盛名的山峰（雪岳山）、最受摄影师青睐的岛屿（南怡岛）以及标志性私家花园（晨静园），尽在13小时内一网打尽。"},"catalog_card":{"thumbnail":"/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp","title":"首尔：雪岳山 + 南怡岛 + 晨静园","priceLabel":"每人起价59美元（原价82美元，立省28%）","shortCardDescription":"从首尔出发的13小时大巴一日游，涵盖韩国三大最热门一日游目的地：雪岳山国立公园（韩国唯一的UNESCO生物圈保护区）、南怡岛（《冬季恋歌》取景地的水杉大道）以及晨静园（拥有5,000种植物的韩国标志性私家植物园）。全程门票已含；配备英语导游；在弘益大学站或明洞站接送。","tags":["首尔出发一日游","大巴游览","自然与花园","韩流地标","全程门票已含"],"rating":0,"reviewCount":0,"slug":"seoul-seoraksan-nami-island-morning-calm-day-tour","subtitle":"雪岳山、南怡岛林荫小道与晨静园主题花园，尽在13小时首尔一日游中一览无余。","region":"首尔 → 江原道 → 京畿道","duration":"13小时","stopsCount":3,"badges":["首尔出发一日游","大型旅游大巴","全程门票已含","13小时全天行程"],"heroImage":"/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp"},"headlineLine1":"首尔一日游","headlineLine2":"雪岳山 + 南怡岛 + 晨静庭园","price":{"amountLabel":"","currency":"USD","per":"person","salePriceUsd":null,"originalPriceUsd":null,"discountPercent":null},"hero":{"imageUrl":"/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp","imagePosition":"center 40%","tagline":"首尔出发13小时大巴一日游，游览韩国三大最受欢迎拍照打卡地：雪岳山、南怡岛林荫小道，以及晨静庭园","pills":["首尔出发一日游","自然风光 + 韩流 + 庭园","大巴游"],"meta":{"duration":"13小时","region":"首尔 → 江原道 → 京畿道","stops":"3个景点","rating":0,"ratingStars":5}},"subnavItems":[{"id":"overview","label":"概览"},{"id":"itinerary","label":"行程安排"},{"id":"details","label":"详情"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"评价"}],"glanceItems":[{"icon":"clock","label":"时长","value":"13小时"},{"icon":"camera","label":"拍照潜力","value":"非常高","level":5},{"icon":"mountain","label":"景色","value":"非常高","level":5},{"icon":"footprints","label":"步行量","value":"适中","level":3},{"icon":"cloud-rain","label":"雨天适合度","value":"适中","level":3},{"icon":"users","label":"家庭适合度","value":"较好","level":4},{"icon":"gauge","label":"节奏","value":"均衡","level":4}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp","location":"雪岳山国立公园","alt":"雪岳山国立公园 — on-route photo","caption":"雪岳山国立公园"},{"id":2,"type":"photo","src":"/images/tours/nami-island/kakaotalk-20260510-222949305-04.webp","location":"南怡岛（南怡洲）","alt":"南怡岛（南怡洲） — gallery image 1","caption":"南怡岛（南怡洲） — photo 1"},{"id":3,"type":"photo","src":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-36-31.webp","location":"晨静树木园","alt":"晨静树木园 — gallery image 1","caption":"晨静树木园 — photo 1"},{"id":4,"type":"photo","src":"/images/tours/seoraksan-national-park/seoraksan-sinheungsa-ulsanbawi.webp","location":"雪岳山国立公园","alt":"雪岳山国立公园 — on-route photo","caption":"雪岳山国立公园"},{"id":5,"type":"photo","src":"/images/tours/seoraksan-national-park/photo-001.webp","location":"雪岳山国立公园","alt":"雪岳山国立公园 — on-route photo","caption":"雪岳山国立公园"},{"id":6,"type":"photo","src":"/images/tours/nami-island/kakaotalk-20260510-222949305-05.webp","location":"南怡岛（南怡洲）","alt":"南怡岛（南怡洲） — gallery image 2","caption":"南怡岛（南怡洲） — photo 2"},{"id":7,"type":"photo","src":"/images/tours/nami-island/chatgpt-image-2026-5-11-01-12-05.webp","location":"南怡岛（南怡洲）","alt":"南怡岛（南怡洲） — gallery image 3","caption":"南怡岛（南怡洲） — photo 3"},{"id":8,"type":"photo","src":"/images/tours/nami-island/nami-metasequoia-sunset-lake.webp","location":"南怡岛（南怡洲）","alt":"南怡岛（南怡洲） — gallery image 6","caption":"南怡岛（南怡洲） — photo 6"},{"id":9,"type":"photo","src":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-43-58.webp","location":"晨静树木园","alt":"晨静树木园 — gallery image 2","caption":"晨静树木园 — photo 2"},{"id":10,"type":"photo","src":"/images/tours/garden-of-morning-calm/garden-of-morning-calm-flowers.webp","location":"晨静树木园","alt":"晨静树木园 — gallery image 3","caption":"晨静树木园 — photo 3"},{"id":11,"type":"photo","src":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-11-01-09-33.webp","location":"晨静树木园","alt":"晨静树木园 — gallery image 4","caption":"晨静树木园 — photo 4"}],"itineraryStops":[{"name":"上车地点（弘益大学站或明洞站）","time":"06:00 / 06:30","number":1,"category":"大巴接送","duration":"30分钟时间窗口","timeUsed":["在预定时间前5分钟抵达所选上车地点（约5分钟）","在指定星巴克/北面门前找到AtoC Korea旅游大巴（约5分钟）","在候车队伍中登上大型旅游大巴（约10分钟）","登车时分发韩英双语印刷版行程卡"],"whyOnRoute":"两处早间上车地点覆盖首尔两大酒店/青旅聚集区：弘益大学周边（麻浦区，深受年轻旅客及短住游客喜爱）和明洞（中区，乐天/新罗/威斯汀等酒店附近的传统旅游区）。弘益大学06:00或明洞06:30出发，是在尊重首尔地铁运营时间（2号线约05:30始发）前提下最早可行的接送时间，也是在10:00前抵达雪岳山、确保3小时有效游览的唯一方式。先弘益、后明洞，经奥林匹克高速公路→首尔-襄阳高速公路，是自然的东北向行驶路线。","description":"上车地点为首尔两处集合点之一：**(1) 星巴克弘益大学站8号出口（麻浦区）**，06:00集合——星巴克店面紧邻8号出口顶端，若需在寒冷天气避风，前一晚至22:00均可在此候车；或 **(2) 明洞站2号出口（中区）**，06:30集合——北面旗舰店是出口旁显眼的地标。\n\n两处上车地点乘坐同一辆大巴，弘益大学乘客先行登车。请在预定时间**前5分钟**抵达所选上车地点，以确保准时出发——13小时行程有赖于10:00前抵达雪岳山。司机兼导游将在登车时分发韩英双语印刷版行程卡，并说明当天行程顺序、如厕停靠点及通常19:00的返程时间。\n\n从明洞（最后上车地点）出发，大巴向东行驶奥林匹克高速公路，再转入首尔-襄阳高速公路，全程约2.5小时抵达雪岳山。"},{"name":"雪岳山国立公园","time":"≈ 10:00","number":2,"category":"国立公园（山岳）","duration":"180分钟（3小时）","timeUsed":["抵达雪岳洞入口 + 司机兼导游行程介绍（约10分钟）","步行前往统一大佛 + 神兴寺（从主停车场步行约15-20分钟）","可选乘坐缆车前往权金城（含排队约30-45分钟）或步行游览飞仙台（约90分钟）","拍照时间 + 返回大巴集合（约15分钟）","可选在神兴寺附近800年古松前拍照（约5分钟）"],"_poi_meta":{"poi_key":"seoraksan_national_park","verified":true,"match":"single_poi","kb_version":"1.27","verified_date":"2026-04-29","sources":["Korea Tourism Organization (VisitKorea — Seoraksan National Park (Outer Seorak) listing + IUCN Green List confirmation)","IUCN Green List of Protected and Conserved Areas (iucngreenlist.org — Seoraksan official entry + 2014 designation + 398.24 km² area)","Korea National Park Service (KNPS — Seoraksan National Park Office official site + endangered species management plan)","UNESCO World Heritage Centre (Mt. Sorak Biosphere Reserve 1982 designation + tentative World Heritage listing)","Wikipedia (Seoraksan National Park — corpus on 30 peaks, 2,000+ animal species, 1,400+ plant species)"]},"highlights":["韩国第 5 座国家公园(1970)与韩国唯一的联合国教科文组织生物圈保护区(1982 年 8 月)","统一大佛:14.6 米 / 108 吨青铜——世界最大青铜坐佛(1997)","神兴寺(新罗 652 年)——曹溪宗总寺;世界最古老禅宗寺院","可选雪岳缆车 1,132 米直达权金城堡观景台(海拔 700 米,1253 年传说)","30 座山峰、2,000 余种动物、1,400-1,562 种植物;珍稀野生动物(麝鹿、长尾斑羚、亚洲黑熊)","公园门票自废止以来 **免费**(原 3,500 韩元);缆车仍收费","**自 2005 年起属 IUCN II 类(国家公园)+ 自 2014 年起列入 IUCN 保护区绿色名录**——韩国首座在试点阶段进入绿色名录的国家公园,与五台山、智异山同列","**自 1982 年 8 月起为韩国唯一的联合国教科文组织生物圈保护区** + **列入联合国教科文组织世界遗产候选名录**——这一双重认定为其他韩国国家公园所未有","**长尾斑羚保护重镇**:稳定种群约 260 只(IUCN 红色名录易危种)——园区设 10 处特别保护区,合计 39 平方公里(占公园总面积 10%)用于濒危物种保护"],"smartNotes":{"photo":"统一大佛(14.6 米青铜)是标志性单帧。缆车视角可框入神兴寺 + 蔚山岩 + 束草市 + 东海。10 月秋叶映花岗岩峰享誉世界。","facilities":"雪岳洞入口设有游客中心、咖啡馆(Dahyang Cafe)、餐厅、礼品店。9:00-14:00 提供免费登山装备租借(16:00 前归还)。入口附近有亚洲黑熊吉祥物雕像。","tip":"缆车票 **不接受提前预订**——10 月排队可超过 1-2 小时。若山雾弥漫,请放弃乘缆车(无视野)。3 小时最佳预算:统一大佛 + 神兴寺 + 飞仙台溪畔步道。务必穿耐磨包脚鞋——部分路段湿滑且多石。"},"whyOnRoute":"单程 2.5 小时车程之所以值得,正源于核心:韩国第 5 座国家公园(1970)与韩国唯一的联合国教科文组织生物圈保护区(1982)——加上世界最大青铜坐佛与世界最古老禅宗寺院,均在小公园入口步行 15 分钟之内。相较于洛山寺备选的优势在于:雪岳洞入口将铺面神兴寺 + 缆车山脊视野 + 飞仙台溪畔步道安置在同一 3 小时窗口内——再无其他雪岳山站点能在如此短的步行预算内集齐这三者。雪岳山兼具 IUCN 绿色名录 + 联合国教科文组织生物圈保护区 + 世界遗产候选地位,使其成为 **韩国知名度最高的自然遗产公园**——这一资质让本日 5 小时往返车程的代价对首次访韩、寻求一座代表性山岳坐标的旅客而言,获得了纯风景类备选(五台山、智异山)无法匹敌的回报。","convenience":{"restroom":"主入口区、缆车站、神兴寺院内、各主要步道沿线","parking":"小公园主入口设有停车场(收费)"},"description":"雪岳山是韩国第 5 座国家公园——1970 年 3 月指定——也是韩国唯一的联合国教科文组织生物圈保护区,1982 年 8 月因卓越的山地生物多样性获此认定。公园横跨 4 市郡,面积约 398 平方公里,30 座命名山峰由大青峰(1,708 米,韩国第 3 高峰)与著名的六柱花岗岩''蔚山岩''锚定。公园门票 **免费**,原由 3,500 韩元代收(代缴神兴寺),已于2023年5月废止 — 现由公共财政拨款维护寺院。\n\n从小公园(外雪岳)主入口出发,典型 3 小时游览覆盖三大亮点:**统一大佛**——14.6 米、108 吨青铜,世界最大青铜坐佛,1997 年为祈愿韩国统一而立,佛座内设观音菩萨小神龛;**神兴寺** 本身,652 年由慈藏律师于新罗时代创建,被誉为世界最古老的禅宗寺院,亦为曹溪宗的总寺;以及可选的 **雪岳缆车**(里程 1,132 米,单程约 10 分钟,直达海拔 700 米的权金城堡观景台——往返成人 16,000 韩元 / 儿童 12,000 韩元,仅现场售票,不接受预订,10 月秋叶高峰常需排队数小时)。\n\n山顶的权金城堡承载一段动人的传说:1253 年高丽王朝抵御蒙古入侵期间,由两位姓权与姓金的将军一日之内修筑而成——故名权-金-城。体力较好且不愿乘缆车的访客可改选轻松的 1.5 公里飞仙台溪畔步道(大部分铺面)、抖动岩(Heundeulbawi)环线(单程石阶 1.5 小时)、或 600 米金刚窟攀登(往返约 1 小时 40 分钟)。","visitBasics":{"hours":"公园全天开放;缆车通常 08:00-17:30(视天气而定);神兴寺 06:00–日落","closed":"全年开放;部分步道因修复定期关闭","admission":"公园 **免费**(原 3,500 韩元已废止);缆车成人往返 16,000 / 儿童 12,000 韩元(仅现场,不预订)","walking":"山脚步道轻松(神兴寺、缆车下站);中等至挑战性徒步(飞仙台 3 公里、蔚山岩陡阶、抖动岩单程 1.5 小时)"},"image":"/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp","images":["/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp","/images/tours/seoraksan-national-park/seoraksan-sinheungsa-ulsanbawi.webp","/images/tours/seoraksan-national-park/photo-001.webp"]},{"name":"南怡岛（南怡洲）","time":"≈ 14:30","number":3,"category":"渡轮小岛&韩剧地标","duration":"120分钟（2小时）","timeUsed":["从加平码头乘渡轮过江（含排队5-10分钟）","沿水杉大道／银杏大道／韩国松林荫道自由漫步——半圈环岛路线约3公里","可选租用自行车（单人7,000韩元／双人14,000韩元，每小时）或乘坐电动蓝色小火车（单程3,000韩元，前往联合国儿童基金会纪念馆）","岛上小食休息（奏鸣曲咖啡厅、糖饼、红薯拿铁）","乘渡轮返回大陆"],"_poi_meta":{"poi_key":"nami_island","verified":true,"match":"single_poi","kb_version":"1.27","verified_date":"2026-04-29","sources":["Korea Tourism Organization (VisitKorea — Nami Island official listing + visa fee schedule)","Naminara Republic Official Site (namisum-en.imweb.me — own corpus on cultural-independence brand)","UNICEF Korea (Nami Island 2010 Child Friendly Park designation + International Children''s Book Festival)","KBS / Korea Times (Winter Sonata 2002 production retrospectives + Japanese tourism boom coverage)","Wikipedia (Namiseom — open corpus on General Nami history + Cheongpyeong Dam 1944 origin)"]},"highlights":["半月形江中岛,面积约 460,000 平方米/周长 5 公里;得名于朝鲜将领南怡(1441–1468)","标志性水杉大道——《冬季恋歌》(2002)经典取景地","自 2006 年起自创''南怡共和国''——自设国旗、货币、护照(旅游概念)","自加平码头 5 分钟轮渡(08:00–21:00,高峰每 10–20 分钟一班)","岛上动物:孔雀(含罕见白孔雀)、鸵鸟、野兔、松鼠","**1944 年成陆**,日本人修建的清平水坝抬升北汉江水位——闵丙焘于 1965 年购岛,1966 年创立京春观光开发公司","**南怡共和国于 2006 年 3 月 1 日宣布成立**,由姜禹铉社长以''文化独立''旅游品牌之名打造——韩国首个以微国家概念为载体的旅游品牌,自设国旗、货币、护照、邮票","**联合国儿童基金会儿童友好公园认证(2010 年)** + 南怡岛艺术与教育每年举办 **600 余场演出/展览/庆典**——单一韩国旅游目的地中颇为罕见","**签证费用**(韩国旅游公社 2026 年官方):普通 ₩19,000(往返轮渡)(单程含摩托艇 ₩29,000);36 个月以下幼儿免费;20 人以上团体享 9 折"],"smartNotes":{"photo":"水杉大道是《冬季恋歌》经典构图——秋季(10 月底至 11 月初金黄)或冬季(雪景)效果最佳。南岸的''恋人银杏树小径''更幽静,出片同样精彩。白孔雀偶尔出现在''恋人小径''附近。","facilities":"岛上餐厅供应韩式家常美味(糖饼、地瓜拿铁、烤牛肋饼)。Sonata 咖啡馆(韩屋风格)是招牌打卡店。加平码头设有受理外卡的售票柜台——自助售票机不接受外卡,请到柜台办理。","tip":"最佳季节:春季(4–5 月樱花)、秋季(10 月金黄银杏 + 红枫)、冬季(12–2 月雪后静谧小径,重现《冬季恋歌》氛围)。请避开周日下午的轮渡排队——建议 16:00 前离岛。Skyline 高空溜索(940 米,约 80 公里/小时,55,000–58,000 韩元含门票)在高峰时段可比轮渡省 15–20 分钟。"},"whyOnRoute":"将南怡岛置于行程之首,可借最强的晨光拍摄树荫大道,并避开下午的轮渡高峰。同时也将岛上的体验放在精力最充沛的时段——晨静树木园与小法国村均偏摄影而非步行,在下午能够轻松压缩。对于 atockorea 的私人包车形式,南怡岛安排在上午还能借力 **首班轮渡优势**(周五至周日及节假日 07:30 自加平码头),客人可在 11:00–14:00 轮渡高峰之前完成 5 公里环岛行(高峰候船时间可长达 30–45 分钟)。私人包车另可选购 38,000 韩元的 Skyline 高空溜索(自 2010 年起为亚洲最长之一,2016 年 2 月登上 KBS《两天一夜》),适合追求戏剧性登岛体验的客人。","convenience":{"restroom":"岛上与加平码头均设多间洗手间","parking":"加平码头小车 6,000 韩元 / 大型车 10,000 韩元(超过 12 小时每小时加收 1,000 韩元)"},"description":"南怡岛以自加平码头出发的 5 分钟轮渡开启一天行程,登上北汉江上一座半月形的江中岛。岛屿面积约 460,000 平方米(140,000 坪),周长约 5 公里,得名于朝鲜时期军事将领南怡(南怡,1441–1468),他在睿宗在位期间因被诬告谋反而 28 岁时遭处决。岛屿原本仅在洪水期才会浮出水面;1944 年日本殖民政府修建清平水坝,水位抬升后南怡岛永久成为江心岛。\n\n2002 年,KBS 电视剧《冬季恋歌》(裴勇俊、崔智友主演)在此取景,使其声名远播——成为 2000 年代初韩流浪潮的催化剂——延续至今每年吸引约 330 万名访客(其中 130 万为外国游客),是继首尔、釜山、济州之后韩国访客量最高的单一旅游目的地。**自 2006 年 3 月 1 日起**,该岛打造出''南怡共和国(Naminara Republic)''品牌,自设国旗、货币(南怡通宝币)、护照与邮政服务——这是一种旅游营销概念,而非真实政治实体。\n\n标志性的水杉大道(《冬季恋歌》经典雪景小径)、南岸的''恋人银杏树小径''、韩松小径,以及由烧酒瓶回收玻璃打造的 Sequoia Bridge,半日内即可悠然走完。截至 2016 年,岛上记录在案的 **年访客量达 330 万人,其中外国游客 130 万,来自 122 个国家**——是首尔、釜山、济州之后单一目的地中外国访客比例最高的景点。南怡岛特别面向 atockorea 的海外华人与东南亚客群配套了普通话/粤语/他加禄语/越南语标识。","visitBasics":{"hours":"岛上 08:00–21:00(末班轮渡时间随季节变动);岛上店铺多于 18:00 关闭","closed":"全年开放","admission":"南怡共和国签证费(含往返轮渡):普通 19,000 韩元 / 优惠 16,000 韩元(70 岁以上长者、初高中生)/ 特殊 13,000 韩元(36 个月以上至小学儿童 + 早鸟 08:00 班次);20 人以上团体享 9 折","walking":"轻松——平坦林荫小径;环岛全程约 5 公里。行动不便者可租借自行车 / 电动车。"},"image":"/images/tours/nami-island/kakaotalk-20260510-222949305-04.webp","images":["/images/tours/nami-island/kakaotalk-20260510-222949305-04.webp","/images/tours/nami-island/kakaotalk-20260510-222949305-05.webp","/images/tours/nami-island/chatgpt-image-2026-5-11-01-12-05.webp","/images/tours/nami-island/nami-metasequoia-sunset-lake.webp"],"imageCredits":[{"url":"/images/tours/nami-island/kakaotalk-20260510-222949305-04.webp","source":"atoc-korea"},{"url":"/images/tours/nami-island/kakaotalk-20260510-222949305-05.webp","source":"atoc-korea"},{"url":"/images/tours/nami-island/chatgpt-image-2026-5-11-01-12-05.webp","source":"atoc-korea"},{"url":"/images/tours/nami-island/nami-metasequoia-sunset-lake.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/nami-island/kakaotalk-20260510-222949305-04.webp","location":"南怡岛（南怡洲）","caption":"南怡岛（南怡洲） — photo 1","alt":"南怡岛（南怡洲） — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/nami-island/kakaotalk-20260510-222949305-05.webp","location":"南怡岛（南怡洲）","caption":"南怡岛（南怡洲） — photo 2","alt":"南怡岛（南怡洲） — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/nami-island/chatgpt-image-2026-5-11-01-12-05.webp","location":"南怡岛（南怡洲）","caption":"南怡岛（南怡洲） — photo 3","alt":"南怡岛（南怡洲） — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/nami-island/nami-metasequoia-sunset-lake.webp","location":"南怡岛（南怡洲）","caption":"南怡岛（南怡洲） — photo 6","alt":"南怡岛（南怡洲） — gallery image 6"}]},{"name":"晨静树木园","time":"≈ 17:00","number":4,"category":"主题植物园","duration":"70分钟","timeUsed":["司机兼导游带领入园并进行简短介绍（约5分钟）","在20个主题子花园中自由漫步（约50分钟）","可选：下沉花园（朝鲜半岛形状）延长拍照时间（约10分钟）","冬季游览：到达时间安排在17:00灯光秀开始之际，可同时欣赏白天花园景色与灯光节点亮瞬间","返回大巴集合（约5分钟）"],"_poi_meta":{"poi_key":"garden_of_morning_calm","verified":true,"match":"single_poi","kb_version":"1.27","verified_date":"2026-04-29","note":"POI verified in KB v1.10 (Batch 7) and reused here unchanged.","sources":["Garden of Morning Calm Official Site (morningcalm.co.kr — own corpus on founder + 1996 opening + 20 sub-gardens)","Korea Tourism Organization (VisitKorea — Lighting Festival listing + lighting-fest schedule)","Gyeonggi Cultural Foundation (ggc.ggcf.kr — official cultural promotion entry on Sunken Garden + 200,000 LEDs)","Sahmyook University Department of Horticulture (Prof. Han Sang-kyung honorary professor profile + garden origin)","Wikipedia (Garden of Morning Calm — corpus on Tagore-derived name + 5,000 species + 330,000 m² total)"]},"highlights":["韩国招牌私家树木园 —— 33万平方米,约5,000种植物","三育大学韩相敬创建;1996年开园(1992年构想)","冬季灯光节2025年12月5日–2026年3月15日,30,000余只LED(韩国首个自然环境灯光节)","20个主题分园 —— 形如朝鲜半岛的下沉花园、月光花园、盆景园、伊甸园","《云画的月光》等韩剧取景地","**1992年构思 / 1994年购地 / 1996年5月11日开园**:三育大学园艺系韩相敬教授与夫人亲自设计与栽培,早期资金困难时甚至卖掉家宅","**入选CNN韩国50大旅游胜地** —— 下沉花园的朝鲜半岛形构图(以10个大小花坛寄托统一愿景)是CNN提及的标志景观","**灯光节使用20万余只环保LED**(12–3月)—— 韩国首个自然环境灯光节;每晚17:00日落后开启","**圆柏(천년향)**为晨静树木园官方代表植物 —— 5,000种之中的招牌树种"],"smartNotes":{"photo":"春(4月樱花)、夏(满目青翠)、秋(10月至11月初秋叶)、冬(日落后灯光节)各有不同观感。灯光节期间的黄昏光之隧道为标志影像。","facilities":"Food Garden供应韩式家常(大酱汤、蔬菜拌饭、雪奶酪炒年糕)。\"Good Morning Coffee\"位于一座韩屋烘焙馆,是园内代表咖啡馆。餐厅20:00打烊。","tip":"灯光节期间(12月5日–3月15日)建议约16:00抵达先看白天的花园,再留至亮灯(约17:00之后)。2月暴雪时最为梦幻,如《冰雪奇缘》场景。"},"whyOnRoute":"将晨静树木园放在白日中段,使整条线路获得最为静谧的视觉篇章——介于南怡岛积极的步行环线与小法国村紧凑村庄之间。每年12月至3月,树木园成为当日的招牌站——灯光节于17:00–21:00达到高峰,正是加平其他景点收摊的时段。中段安排同时捕捉了树木园摄影声誉所依赖的**过渡性下午光**:秋季14:00–16:00柔和的侧光最能呈现枫叶色彩,冬季同一时段则可让中场休憩与**17:00灯光节亮灯**(12–3月)无缝衔接,让您的私人包车客人以一张门票获得两座迥异的视觉花园(白天的树木园 + 夜晚的LED灯节)。","convenience":{"restroom":"多处,有指示牌","parking":"大型免费停车场;投币式存物柜1,500–2,000韩元(仅500韩元硬币)"},"description":"从南怡岛南行约30分钟,晨静树木园是韩国的招牌私家树木园——约33万平方米的精致景观,约5,000种植物。1992年构想、1996年向公众开放,由三育大学韩相敬教授亲自设计与栽种,他甚至一度变卖家宅以筹建项目;名字来自韩国\"朝鲜——晨静之地\"的旧称。园内20个主题分园——包含形如朝鲜半岛的\"下沉花园\"、故乡屋花园、盆景园、月光花园、天空之路、伊甸园等——各具视觉性格,亦是众多韩剧的取景地,例如《云画的月光》。\n\n每年12月初至次年3月中旬,园区举办韩国首个自然环境灯光节——2025–2026届为2025年12月5日至2026年3月15日,30,000余只LED铺满园区,日落后将花园化作冬日仙境。灯光节时段周日–五延长至11:00–21:00,周六11:00–23:00;非灯光节期为08:30–19:00,18:00停止入园。**\"Garden of Morning Calm\"**之名出自印度诗人泰戈尔1929年称韩国为\"晨静之国\"的诗句。\n\n韩相敬1992年于美国担任交换教授时萌发构想,被那里的世界级私家花园所启发。1994年购地——原为刀耕火种留下的荒石地。**韩教授与夫人亲自设计、亲手劳作**;经济困难时期,他们卖掉家宅,在园内一处小屋居住,以延续建设。1996年5月11日首次以10个主题区开园,如今已扩展至33万平方米、20个主题分园。","visitBasics":{"hours":"春秋08:30–19:00(18:00停止入园);冬季灯光节周日–五11:00–21:00,周六11:00–23:00","closed":"全年开放","admission":"成人11,000韩元 / 65岁以上长者9,000韩元 / 13–18岁青少年8,500韩元 / 3–12岁儿童7,500韩元(凭票优惠相邻动物园2,000韩元)","walking":"中等 —— 20个主题分园之间起伏路径较多;主环路大部分婴儿车可通行"},"image":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-36-31.webp","images":["/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-36-31.webp","/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-43-58.webp","/images/tours/garden-of-morning-calm/garden-of-morning-calm-flowers.webp","/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-11-01-09-33.webp"],"imageCredits":[{"url":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-36-31.webp","source":"atoc-korea"},{"url":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-43-58.webp","source":"atoc-korea"},{"url":"/images/tours/garden-of-morning-calm/garden-of-morning-calm-flowers.webp","source":"atoc-korea"},{"url":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-11-01-09-33.webp","source":"atoc-korea"},{"url":"/images/tours/garden-of-morning-calm/garden-of-morning-calm-flowers.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-36-31.webp","location":"晨静树木园","caption":"晨静树木园 — photo 1","alt":"晨静树木园 — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-10-10-43-58.webp","location":"晨静树木园","caption":"晨静树木园 — photo 2","alt":"晨静树木园 — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/garden-of-morning-calm/garden-of-morning-calm-flowers.webp","location":"晨静树木园","caption":"晨静树木园 — photo 3","alt":"晨静树木园 — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/garden-of-morning-calm/chatgpt-image-2026-5-11-01-09-33.webp","location":"晨静树木园","caption":"晨静树木园 — photo 4","alt":"晨静树木园 — gallery image 4"}]},{"name":"返回首尔（弘益大学站或明洞站）","time":"≈ 19:00","number":5,"category":"返程送客","duration":"车程60分钟","timeUsed":["大巴离开晨静苑（约18:10）","经首尔—襄阳高速公路驶向首尔（约60分钟，视路况而定）","在明洞站2号出口下车（约19:00）","在弘益大学站8号出口下车（约19:30）"],"whyOnRoute":"返程按接客顺序反向送客：**明洞站优先下车**（约19:00），因其经首尔—襄阳高速公路距晨静苑更近，其次为**弘益大学站下车**（约19:30）。13小时的行程时长以明洞返程时间为基准——有晚餐预约的宾客建议预订20:00或更晚的时段，以留出充足的交通缓冲时间。周五及周日晚间高速公路交通较为拥堵，返程可能延误30分钟——如您有航班或重要约定，请提前告知司机兼导游。","description":"After Morning Calm, the coach takes the **Seoul-Yangyang Expressway** westbound back into Seoul. Drop-offs are sequenced: **Myeongdong Station Exit 2 first at approximately 19:00**, then **Hongik University Station Exit 8 at approximately 19:30**. Both drop-off points are at the same locations as morning pickup. \n\nGuests connecting to evening shows in Hongdae or dinner reservations in Myeongdong should plan for **20:00 or later** to allow a comfortable buffer for traffic, particularly on Friday and Sunday evenings when the expressway runs heavier."}],"routeFlowStops":[{"name":"接客（弘益大学 / 明洞）","type":"origin","theme":"首尔接客"},{"name":"雪岳山国立公园","type":"primary","theme":"山岳与寺庙"},{"name":"南怡岛","type":"primary","theme":"韩剧之岛"},{"name":"晨静苑","type":"primary","theme":"主题花园"},{"name":"返回首尔","type":"return","theme":"下车送达"}],"routePhases":[{"phase":"首尔 → 雪岳山","duration":"≈ 3小时","description":"06:00于弘大、06:30于明洞接客，沿首尔-襄阳高速公路向东北方向驾车约2.5小时，于10:00抵达雪岳山。"},{"phase":"雪岳山","duration":"≈ 3小时","description":"小公园入口：统一大佛、神兴寺，可选乘缆车前往权金城，或沿飞仙台溪边漫步。"},{"phase":"雪岳山 → 南怡岛（含午餐）","duration":"≈ 2.5小时","description":"经麟蹄-洪川-春川走廊向南行驶；途中在当地江原道餐厅用午餐（自费）。"},{"phase":"南怡岛","duration":"≈ 2小时","description":"乘渡轮往返，在南怡岛国游览水杉大道、银杏大道及赤松大道。"},{"phase":"晨静苑 & 返程","duration":"≈ 2小时","description":"向南驾车30分钟抵达晨静苑（游览70分钟），再沿首尔-襄阳高速公路行驶约1小时返回首尔。"}],"routeShapeIntro":{"title":"首尔一日行程脉络","subtitle":"06:00/06:30于弘大/明洞早接，向东北驾车约2.5小时，以雪岳山作为全天山地核心；经麟蹄-春川走廊返回，前往南怡岛享受林荫渡轮之旅；向南30分钟至晨静苑，迎接全天最温柔的收官时刻（冬季点亮灯光节）；于19:00-19:30返回首尔。"},"whyTourWorks":{"bestFor":["首次访韩、希望一天内打卡韩国三大标志性一日游胜地的旅行者","因《冬日恋歌》水杉大道而前来的情侣及韩流粉丝","希望集山脉、岛屿与花园三重体验于一身的摄影爱好者","以首尔为大本营、能接受13小时全天行程以实现最大游览量的旅行者"],"lessIdealFor":["希望慢节奏单站体验的旅行者","不想从早上06:00开始、承受长达13小时行程的旅客","年幼儿童（6岁以下），可能难以承受长时间的大巴车程","行动不便的旅行者——雪岳山路段有阶梯和岩石地形"],"routeLogicSections":[{"title":"行程节奏与地理布局","icon":"sun","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"先向东北，返程向西","detail":"雪岳山是最远的目的地（单程约2.5小时车程），因此在体力最充沛时优先游览，南怡岛和晨静植物园则安排在经由春川—加平走廊的自然返程路线上——全程无需折返。"},{"label":"山地 → 岛屿 → 花园","detail":"全天行程从高体力消耗（雪岳山阶梯及可选缆车）过渡到中等强度（南怡岛平坦的环岛步道），再到轻松惬意（晨静植物园漫步）。拍摄风格也依次从花岗岩山脊 → 林荫小道 → 精心布置的植物园景观逐步演变。"},{"label":"冬季特别惊喜","detail":"12月5日至3月15日期间，17:00抵达晨静植物园，既可欣赏白天的园区美景，又能赶上灯光节的璀璨时刻——33万平方米的园区内亮起逾20万盏LED灯，这种一票双享的体验，大多数自助旅行者很难如此完美地把握时机。"}]},{"title":"为何13小时足以完成这一切","icon":"clock","iconBg":"bg-pink-50/80","iconColor":"text-pink-600","items":[{"label":"所有门票均已包含","detail":"南怡岛渡轮（₩19,000）和晨静植物园（₩11,000）门票均已包含在团费中，无需在各站另行购票。唯一的自费项目是可选的雪岳山缆车（来回₩16,000），需在现场自付。"},{"label":"首尔两处上车地点","detail":"弘大（麻浦区）06:00及明洞（中区）06:30，覆盖首尔两大主要住宿集中区——旅客可选择距离自己酒店最近的上车地点。"},{"label":"以户外景点为主","detail":"三个景点均以户外活动为主，大巴车厢是唯一的室内环节。天气适宜时体验极佳；大雨天气会导致缆车停运，但其他所有景点仍可正常游览。"}]},{"title":"如实说明行程局限","icon":"info","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"雪岳山有阶梯（缆车为可选项目）","detail":"新兴寺台地和可选的摇晃石环线均有阶梯。统一大佛+新兴寺步道为平坦路段，无障碍通行；缆车采用吊椅式乘坐方式（缆车本身无阶梯），但权金城观景台顶部设有岩石台阶。"},{"label":"缆车无法提前预订","detail":"雪岳山缆车门票仅限现场购买，十月旺季可能需要排队1至2小时。若天空多雾或队列过长，推荐的替代方案为飞仙台溪边步道（路面平坦、铺装良好，往返约90分钟），同样契合3小时的行程预算。"},{"label":"全天行程从06:00出发，历时较长","detail":"本行程为大巴团体游，全程共约13小时，其中大巴车程约4.5小时。如需缩短行程时长或自由安排停留时间，建议选择我们的私人包车一日游（酒店门口接送，时间灵活定制）。"}]}]},"practicalAccordionItems":[{"id":"pickup","title":"上下车地点","preview":"首尔两处上车地点：弘益大学站8号出口星巴克，06:00……","content":["首尔两处上车地点：**弘益大学站8号出口星巴克，06:00**（麻浦区），以及**明洞站2号出口（The North Face旗舰店），06:30**（中区）。","两处上车地点共乘同一辆大巴，请提前5分钟到达所选上车地点。","返程按相反顺序送达：**明洞约19:00，弘益大学约19:30**。","周五／周日晚间可能因高速公路交通拥堵而延误约30分钟——若您有固定的后续安排，请提前告知导游。"]},{"id":"what-to-bring","title":"着装与携带物品","preview":"适合雪岳山步道的舒适包头步行鞋（部分路段较为崎岖）……","content":["适合雪岳山步道的舒适包头步行鞋（部分路段较为崎岖）。","10月至3月请备好保暖衣物；雪岳山海拔较高，气温比首尔低5至7°C。","相机或智能手机（南怡岛水杉大道与晨静树木园是拍照的绝佳亮点）。","请备好现金及银行卡，用于午餐（约₩10,000–15,000）及可选乘坐的雪岳山缆车（₩16,000）。","若未用早餐便出发，请自备轻便零食——首次用餐停靠约在前往南怡岛途中的13:00至13:30。"]},{"id":"weather-policy","title":"天气政策","preview":"全年运营。","content":["全年运营。","小雨：行程照常进行——南怡岛和晨静树木园雨中别有韵味；穿防滑鞋可正常行走雪岳山低海拔步道。","大雨：暴风雨天气下雪岳山缆车通常暂停运营（如已预付则予以退款）；导游将带领游客改走飞仙台步道或延长神兴寺参观时间。","台风级别天气或高速公路封闭：提供全额退款或免费改期服务。"]},{"id":"inclusions","title":"费用包含","preview":"首尔两处上车服务、大巴车、英语导游、南怡岛及晨静树木园门票……","content":["首尔两处上下车地点、配备空调的大型大巴、持证英语导游。","**南怡岛渡轮往返 + 南怡岛共和国签证费（₩19,000）— 已含**。","**晨静园门票（₩11,000）— 已含**。","**雪岳山国家公园入场费 — 免费（近期已取消收费）**。","**不含**：途中午餐（约₩10,000-15,000）、可选雪岳山缆车（₩16,000往返，仅限现场购票）。"]},{"id":"language","title":"语言","preview":"主要导览语言：英语。","content":["主要导览语言：英语。","可提供中文导游服务，需提前3天或以上预约。","全天菜单点餐、路牌识别及市集互动均使用韩语，由导游负责翻译。"]},{"id":"walking","title":"步行与地形","preview":"中等难度。","content":["中等难度。","雪岳山：新兴寺山脚处为简单难度；飞仙台步道为中等难度；如选择흔들바위（晃石）或蔚山岩（含阶梯），则为较高难度。","南怡岛：平坦的林荫大道，路面铺装良好；通常步行约3公里，用时约2小时。","晨静园：地势起伏，以铺装园路为主。","总步行距离约4-5公里，另加可选的雪岳山阶梯路段。","婴儿车在南怡岛全程可用，晨静园部分路段可用；雪岳山上部步道不适合使用婴儿车。"]},{"id":"lunch","title":"午餐（自费）","preview":"午餐安排在从雪岳山前往南怡岛的途中，约13:30用餐……","content":["午餐安排在从雪岳山前往南怡岛的途中，约13:30，在麟蹄—春川沿线的当地餐厅用餐。","常见选择：春川辣炒鸡排（该地区最具代表性的料理——香辣翻炒鸡肉配卷心菜与年糕）、刀削面或拌饭（约₩10,000-15,000）。","如需素食或清真餐食，请提前告知，可提前安排——请在预订时备注说明。"]},{"id":"cancellation","title":"取消政策","preview":"接送前24小时内可免费取消。","content":["接送前24小时内可免费取消。","出发前24小时内取消：退款50%。","未出现或错过接车：不予退款——但如在接车时间10分钟内联系AtoC Korea运营团队，若车辆提前到达，司机可能会短暂等候。"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"请参阅季节说明"},"tomorrow":{"temp":"—","label":"请参阅季节说明"},"_seasonalSummary":"Seoul + Gangwon: temperate four-season climate. Seoraksan is 5-7°C cooler than Seoul year-round. Hot humid summers (Jun-Aug), crisp cold winters (Dec-Feb), with prime seasons in spring (April cherry blossoms) and autumn (October-November foliage)."},"seasonalVariations":[{"season":"春季（3月－5月）","description":"南怡岛和晨静苑的樱花盛开于四月上中旬；雪岳山的杜鹃花与连翘于四月下旬绽放。全天巴士游最为舒适的气候。"},{"season":"夏季（6月－8月）","description":"雪岳山步道绿意盎然；南怡岛林荫大道绿荫最浓。七月雨季可能缩短雪岳山游览时间。晨静苑的绣球花和玫瑰于六月进入盛花期。"},{"season":"秋季（9月－11月）","description":"韩国最具代表性的季节——十月中旬至十一月初，雪岳山红叶举世闻名；南怡岛的银杏与水杉在十月下旬至十一月间染成金黄；晨静苑的菊花与枫叶在十月最为绚烂。需求最旺——请提前两周以上预订。"},{"season":"冬季（12月－2月）","description":"**冬季是本行程标志性的\"冬日仙境\"季节**：雪岳山花岗岩山峰白雪皑皑；南怡岛白雪覆盖的水杉大道重现《冬季恋歌》的经典意境；晨静苑冬季灯光节（12月5日至3月15日）在园内点亮逾20万盏LED灯——行程于17:00抵达，既可欣赏白昼园景，又恰好赶上灯光点亮时刻。"}],"bookingTrustItems":[{"icon":"check-circle","title":"全程门票费用已包含","description":"南怡岛渡轮 + 晨静苑门票套餐","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600","body":"南怡岛渡轮（₩19,000）及晨静苑（₩11,000）门票已预付至行程费用中——无需在各景点单独排队购票。雪岳山入园免费（近期已取消收费）。门票总节省：约₩30,000。"},{"icon":"users","title":"持证英语导游","description":"韩国持证旅游导游","iconBg":"bg-pink-50/80","iconColor":"text-pink-600","body":"持韩国旅游组织颁发执照、英语流利的专业导游；如提前预约，可安排中文导游服务。导游讲解内容涵盖雪岳山新罗时代寺庙历史、南怡岛《冬季恋歌》的历史遗产，以及晨静苑创始人的故事。"},{"icon":"shield","title":"价格透明","description":"无隐性购物停留","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","body":"没有人参店，没有免税店，没有佣金纪念品绕道。13小时行程的每一分钟都在景点游览或途中行进——您预订的就是您所体验的。"}],"bookingSupportSteps":[{"timing":"立即","title":"即时确认","detail":"含接送地点选择的预订确认","description":"即时预订确认，含弘益/明洞接送地点选择。"},{"timing":"出发前一天","title":"接送详情","detail":"通过WhatsApp/短信发送精确接送地点及车辆信息","description":"出发前一天发送天气预报、大巴车牌号及任何季节性路线备注（晨静之园灯光节时间、雪岳山红叶高峰期等）。"},{"timing":"出发当天早上","title":"接送确认","detail":"导游在出发前10分钟于接送地点确认身份","description":"导游从05:50起在弘益大学8号出口星巴克等候；从06:20起在明洞2号出口（NorthFace）等候。导游及大巴照片将于前一晚发送至您的WhatsApp。"},{"timing":"行程中","title":"行程中支援","detail":"每个景点均有导游讲解 + 24小时全天运营支持","description":"导游现场讲解雪岳山公元652年新罗时代的建寺历史、南怡岛1944年清平水坝的起源及2002年《冬季恋歌》的传奇，以及晨静之园1992年的构想与1996年的开园历程。"},{"timing":"行程结束","title":"两个返程下车地点","detail":"明洞约19:00 / 弘益约19:30","description":"大巴返程时按相反顺序在两个接送地点停靠。"},{"timing":"行程结束后","title":"评价与后续跟进","detail":"可选行程后评价","description":"行程结束后发送反馈请求；您在首尔剩余行程的餐厅或景点推荐将于当天回复。"}],"staticQuestions":[{"id":"duration","question":"这个行程有多长时间？","answer":"从弘益大学站06:00或明洞06:30接客，全程门到门约13小时。返回首尔时间为19:00（明洞）至19:30（弘益大学站）之间。"},{"id":"pickup","question":"具体在哪里上车？","answer":"共有两个上车地点：(1) 06:00 **弘益大学站8号出口星巴克**（麻浦区）——出口顶部的星巴克；或 (2) 06:30 **明洞站2号出口**（中区）——出口顶部的NorthFace旗舰店。预订时请选择距您酒店最近的地点。"},{"id":"drop-off","question":"在哪里下车？","answer":"下车地点与上车相同，顺序相反：约19:00先到明洞2号出口，约19:30再到弘益大学站8号出口。周五/周日晚间因高速公路拥堵，可能晚30分钟。"},{"id":"admissions","question":"门票是否包含在内？","answer":"两个收费景点的门票已包含：**南怡岛渡轮往返（₩19,000）和晨静树木园门票（₩11,000）均已包含**。**雪岳山国家公园入场免费**（原3,500韩元费用已于2023年5月取消）。**唯一需自费的可选项目是雪岳缆车**（往返₩16,000），仅限现场购票——费用自理。"},{"id":"cable-car","question":"我应该乘坐雪岳缆车吗？","answer":"天气晴朗时山脊景色极为壮观，但门票无法提前预订，10月赏秋叶高峰期现场排队可能超过1-2小时。若天气多雾，建议跳过（无景可赏）。推荐的替代选择是**飞仙台溪边步道**（铺装路面1.5公里，从入口出发约90分钟往返），与3小时雪岳山游览时间完全吻合。"},{"id":"winter-sonata","question":"南怡岛是《冬季恋歌》的拍摄地吗？","answer":"是的——南怡岛的水杉林荫大道是2002年KBS电视剧《冬季恋歌》（裴勇俊、崔智友主演）的标志性拍摄地。这条大道四季皆适合拍照，但秋季（金黄色的10-11月）和冬季（白雪覆盖）最为动人。"},{"id":"lighting-festival","question":"我能看到晨静树木园灯光节吗？","answer":"如果您在**12月5日至3月15日**之间预订即可——行程17:00抵达晨静树木园，既能游览白天的花园，又能赶上灯光亮灯时刻。节日期外（4月至11月），晨静树木园是全天最悠闲的植物主题章节，可欣赏各季花卉（4月樱花、6月绣球花、10月红叶）。"},{"id":"kids","question":"这个行程适合儿童吗？","answer":"适合，6岁及以上均可参加。06:00出发的13小时行程对年幼儿童来说较为漫长——建议8岁以上更为舒适。孩子们通常喜欢南怡岛的孔雀和水杉桥，以及冬季晨静树木园的灯光节。雪岳山部分路段有礁石，但神兴寺和缆车均适合儿童游览。"},{"id":"seniors","question":"这个行程适合老年人吗？","answer":"身体状况良好的老年人完全没问题——全天主要的体力消耗是南怡岛和晨静树木园各2-3公里的游览路线（均为平坦或起伏地形）。在雪岳山，神兴寺路段轻松可达；\"摇摇石\"（흔들바위）环线需要爬台阶，可跳过。行动不便的旅客建议改选我们的私人包车一日游。"},{"id":"lunch","question":"午餐是否包含在内？","answer":"不包含——午餐需自费（每人约₩10,000-15,000）。大巴约13:30在从雪岳山前往南怡岛途中的一家江原道本地餐厅停靠。当地常见选择：**春川铁板鸡**（甜辣炒鸡肉配卷心菜和年糕）、**刀切面**（刀削面汤）或拌饭。如提前告知，可安排素食及清真友好选项。"},{"id":"language","question":"导游会说什么语言？","answer":"主要为英语。如需中文导游，可提前预约——需提前3天以上预订。导游全天负责菜单翻译及与摊贩的沟通互动。"},{"id":"best-season","question":"这个行程最佳的游览季节是什么时候？","answer":"**秋季（10月中旬至11月初）**是韩国最具代表性的赏叶季——雪岳山红叶享誉世界，南怡岛银杏与枫树林荫道金色盛放。**冬季（12月至3月）**是\"冬日仙境\"季节，可欣赏雪岳山雪景、南怡岛的《冬季恋歌》氛围，以及晨静树木园灯光节。**春季（4月）**南怡岛和晨静树木园樱花盛开。10月出行请提前2周以上预订。"},{"id":"rain","question":"如果下雨怎么办？","answer":"小雨：行程按计划进行——只要穿着合适的鞋子，三个景点均可在雨中步行游览。大雨：雪岳山缆车通常会暂停运营（导游将改为游览飞仙台步道）；南怡岛和晨静树木园仍正常运营。台风级天气或高速公路封闭：提供全额退款或改期服务。"},{"id":"private","question":"这与私人包车游相比有何不同？","answer":"这是一款经济实惠的大巴团体游（每人59美元）。我们的**私人包车一日游**选项提供酒店门口接送、灵活的时间安排、可定制行程（例如增加小法国村或取消雪岳山），私人车辆费用通常为4人团每组300至450美元——5人及以上时人均费用相当。如注重经济实惠请选择大巴团体游，如注重灵活性与舒适度请选择私人包车。"},{"id":"walking","question":"需要步行多远？","answer":"三个景点合计约步行4至5公里，若选择乘坐缆车，还需加上雪岳山缆车站台台阶的路程。建议穿着结实的包头鞋（雪岳山部分路段可能较为潮湿或崎岖）。"}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"pickup_dropoff":{"primary":{"name":"弘益大学站8号出口星巴克","address":"首尔麻浦区杨花路（弘益大学站8号出口星巴克前）","time":"06:00 pickup / 19:30 drop-off","instructions":"请在弘益大学站8号出口正上方的星巴克门前与导游会合。请认准AtoC Korea的指示牌及候车队列中的大型大巴。"},"alternates":[{"name":"明洞站2号出口（NorthFace旗舰店）","address":"首尔中区退溪路（明洞站2号出口NorthFace旗舰店）","time":"06:30 pickup / 19:00 drop-off","instructions":"请在明洞站2号出口顶部的NorthFace旗舰店前与导游会合。"}]},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"seoul-seoraksan-nami-island-morning-calm-day-tour","product_type":"bus","route_type":"fixed_route","destination_region":"seoul_gangwon","region_type":"gangwon_seoraksan","vehicle_type":"large_coach","duration_hours":13,"region_tags":["seoul_mapo","seoul_jung","gangwon_sokcho","gyeonggi_gapyeong"],"theme_tags":["national_park","mountain","buddhist_temple","k_drama_filming","themed_garden","hallyu_landmark"],"poi_tags":["seoraksan_national_park","nami_island","garden_of_morning_calm"],"pace_level":0.7,"walking_level":0.6,"scenic_level":1,"photo_level":1,"culture_level":0.85,"relax_level":0.5,"first_time_fit":1,"family_fit":0.7,"senior_fit":0.6,"couple_fit":1,"solo_traveler_fit":0.9,"active_traveler_fit":0.85,"adult_family_fit":0.95,"family_with_teens_fit":0.95,"young_kids_fit":0.4,"senior_active_fit":0.75,"senior_general_fit":0.55,"mobility_friendly_fit":0.4,"stroller_fit":0.55,"one_day_fit":1,"same_day_flight_fit":0.1,"rain_fit":0.5,"value_for_money_fit":1,"iconic_landmark_fit":1,"cafe_fit":0.5,"food_fit":0.5,"nature_fit":1,"beach_fit":0.1,"nightlife_fit":0.1,"shopping_fit":0.25,"no_shopping_fit":1,"local_culture_fit":0.7,"storytelling_fit":0.9,"unesco_fit":0.55,"intangible_heritage_fit":0.5,"indoor_ratio":0.1,"weather_sensitivity":0.65,"comfort_level":0.55,"budget_fit":1,"premium_fit":0.2,"small_group_fit":0.15,"private_fit":0.05,"bus_fit":1,"price_band":"budget","pickup_base":"seoul_central","return_time_band":"19:00-19:30","duration_band":"13h","min_recommended_age":8,"hard_constraints":{"avoidIf":["mobility_limited","wheelchair_required"],"notIdealFor":["very_low_mobility","young_kids_under_6"]},"walking_notes":["13-hour day with ~4-5 km total walking.","Seoraksan paths rocky in places; Nami and Morning Calm flat.","Closed-toe shoes recommended.","Cable car at Seoraksan optional and not included."],"keywords":["seoul seoraksan day tour","nami island day trip","garden of morning calm tour","seoul winter wonder tour","seoraksan nami one day"],"synonym_hints":["seoul to seoraksan day tour","korea three signature stops day trip","seoul winter sonata tour"],"seasonality":"year_round","pickup_base_normalized":"seoul","vehicle_type_legacy":"bus_coach","anchor_poi_keys":["seoraksan_national_park","nami_island","garden_of_morning_calm"],"private_tour_fit":0.05,"customizable_route_fit":0.05,"flexibility_fit":0.2,"fixed_itinerary_fit":1,"national_park_fit":1,"buddhist_temple_fit":0.6,"k_drama_filming_fit":1,"winter_sonata_fit":1,"themed_garden_fit":1,"history_culture_fit":0.65,"religious_history_fit":0.45,"premium_dining_fit":0.15,"seasonal_fit":1,"winter_lighting_festival_fit":1,"autumn_foliage_fit":1,"china_mainland_market_fit":0.85,"korea_domestic_market_fit":0,"taiwan_market_fit":1,"singapore_market_fit":1,"hong_kong_market_fit":1,"china_diaspora_overseas_market_fit":1,"se_asia_market_fit":1,"us_market_fit":0.95,"europe_market_fit":0.95,"australia_market_fit":0.95,"japan_market_fit":1,"first_time_korea_fit":1,"seoul_day_trip_fit":1,"english_speaking_guide_provided":true,"chinese_speaking_guide_available_on_advance_notice":true,"japanese_speaking_guide_available_on_advance_notice":true},"matching_metadata":{"matching_schema":"match_tours_embedded_v2","embedded_for":"atockorea_tour_marketplace","primary_themes":["nature","scenic","national_park","k_drama_filming"],"secondary_themes":["buddhist_temple","themed_garden","hallyu_landmark","mountain"],"best_for":["first_time_korea","couples","solo_travelers","nature_lovers","photographers","k_drama_fans"],"not_recommended_for":["mobility_limited","very_young_children","shoppers","nightlife_seekers"],"source_of_truth_note":"Coach-tour combining Seoraksan + Nami Island + Garden of Morning Calm from Seoul. Attraction content reused from seoul-seoraksan-national-park-sokcho-beach-day-trip (Seoraksan) and seoul-private-nami-morning-calm-petite-france (Nami, Morning Calm). Sources: KTO VisitKorea, IUCN Green List, UNESCO, KNPS, Garden of Morning Calm official, Naminara Republic official, KBS Winter Sonata records, Wikipedia.","audit_summary":"Seoul-based 13-hour coach day trip on the classic Seoraksan + Nami + Morning Calm circuit. Direct equivalent on GetYourGuide market is the $82 ''From Seoul: Seoraksan, Nami Island, Garden of Morning Calm'' (t1137310)."}}'::jsonb
