":1,"china_diaspora_overseas_market_fit":1,"se_asia_market_fit":1,"us_market_fit":0.95,"europe_market_fit":0.95,"australia_market_fit":0.95,"japan_market_fit":1,"first_time_korea_fit":1,"seoul_day_trip_fit":1,"english_speaking_guide_provided":true,"chinese_speaking_guide_available_on_advance_notice":true,"japanese_speaking_guide_available_on_advance_notice":true},"matching_metadata":{"matching_schema":"match_tours_embedded_v2","embedded_for":"atockorea_tour_marketplace","primary_themes":["nature","scenic","national_park","k_drama_filming"],"secondary_themes":["buddhist_temple","themed_garden","hallyu_landmark","mountain"],"best_for":["first_time_korea","couples","solo_travelers","nature_lovers","photographers","k_drama_fans"],"not_recommended_for":["mobility_limited","very_young_children","shoppers","nightlife_seekers"],"source_of_truth_note":"Coach-tour combining Seoraksan + Nami Island + Garden of Morning Calm from Seoul. Attraction content reused from seoul-seoraksan-national-park-sokcho-beach-day-trip (Seoraksan) and seoul-private-nami-morning-calm-petite-france (Nami, Morning Calm). Sources: KTO VisitKorea, IUCN Green List, UNESCO, KNPS, Garden of Morning Calm official, Naminara Republic official, KBS Winter Sonata records, Wikipedia.","audit_summary":"Seoul-based 13-hour coach day trip on the classic Seoraksan + Nami + Morning Calm circuit. Direct equivalent on GetYourGuide market is the $82 ''From Seoul: Seoraksan, Nami Island, Garden of Morning Calm'' (t1137310)."}}'::jsonb
